var QUESTIONS_THEORY_9 = [
// EASY - MCQ (28 Questions)
{type:"mcq",diff:"easy",en:{q:"What does DBMS stand for in computer science?",opts:["Data Broadcasting Management System","Database Management System","Digital Business Management Software","Data Base Manipulation System"],ans:1,exp:"DBMS stands for Database Management System. It is a specialized software application used to create, manage, retrieve, and update data within a database. It serves as an interface between the database and the end-users or application programs, ensuring data is consistently organized and easily accessible."},hi:{q:"कंप्यूटर विज्ञान में DBMS का पूर्ण रूप क्या है?",opts:["डेटा ब्रॉडकास्टिंग मैनेजमेंट सिस्टम","डेटाबेस मैनेजमेंट सिस्टम","डिजिटल बिजनेस मैनेजमेंट सॉफ्टवेयर","डेटा बेस मैनिपुलेशन सिस्टम"],ans:1,exp:"DBMS का पूर्ण रूप डेटाबेस मैनेजमेंट सिस्टम है। यह एक विशेष सॉफ्टवेयर एप्लिकेशन है जिसका उपयोग डेटाबेस के भीतर डेटा बनाने, प्रबंधित करने, पुनर्प्राप्त करने और अपडेट करने के लिए किया जाता है। यह डेटाबेस और अंतिम उपयोगकर्ताओं के बीच एक इंटरफ़ेस के रूप में कार्य करता है, यह सुनिश्चित करता है कि डेटा सुसंगत और सुलभ है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary function of an RDBMS?",opts:["To create presentations and slide shows","To store data in a collection of logically related two-dimensional tables","To manage network routing protocols","To edit digital images and graphics"],ans:1,exp:"RDBMS stands for Relational Database Management System. Its primary function is to store and manage data in structured, two-dimensional tables consisting of rows and columns. These tables can be logically linked or related to each other based on common fields, enabling complex data queries and reporting."},hi:{q:"RDBMS का प्राथमिक कार्य क्या है?",opts:["प्रस्तुतियां और स्लाइड शो बनाने के लिए","तार्किक रूप से संबंधित दो-आयामी तालिकाओं (tables) के संग्रह में डेटा संग्रहीत करने के लिए","नेटवर्क राउटिंग प्रोटोकॉल का प्रबंधन करने के लिए","डिजिटल छवियों और ग्राफिक्स को संपादित करने के लिए"],ans:1,exp:"RDBMS का अर्थ रिलेशनल डेटाबेस मैनेजमेंट सिस्टम है। इसका प्राथमिक कार्य पंक्तियों और स्तंभों से युक्त संरचित, दो-आयामी तालिकाओं में डेटा को संग्रहीत और प्रबंधित करना है। जटिल डेटा क्वेरी को सक्षम करने के लिए सामान्य फ़ील्ड के आधार पर इन तालिकाओं को एक-दूसरे से तार्किक रूप से जोड़ा जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"In a relational database, what is another term used for a 'Row'?",opts:["Attribute","Field","Record or Tuple","Domain"],ans:2,exp:"In the terminology of relational databases, a 'Row' is formally known as a 'Tuple' or commonly referred to as a 'Record'. Each row represents a single, complete set of related data entities within a table, such as all the information pertaining to one specific employee or one particular product."},hi:{q:"रिलेशनल डेटाबेस में, 'रो' (Row) के लिए प्रयुक्त एक अन्य शब्द क्या है?",opts:["एट्रीब्यूट (Attribute)","फ़ील्ड (Field)","रिकॉर्ड या टुपल (Record or Tuple)","डोमेन (Domain)"],ans:2,exp:"रिलेशनल डेटाबेस की शब्दावली में, एक 'पंक्ति' (Row) को औपचारिक रूप से 'टुपल' के रूप में जाना जाता है या आमतौर पर 'रिकॉर्ड' कहा जाता है। प्रत्येक पंक्ति एक तालिका के भीतर संबंधित डेटा संस्थाओं के एकल, पूर्ण सेट का प्रतिनिधित्व करती है, जैसे कि एक विशिष्ट कर्मचारी से संबंधित सभी जानकारी।"}},
{type:"mcq",diff:"easy",en:{q:"What is the fundamental database object used to store data in MS Access?",opts:["Form","Query","Table","Report"],ans:2,exp:"The 'Table' is the fundamental, foundational object in any database system, including MS Access. It is the actual storage container where raw data is physically kept in a structured format of rows and columns. All other database objects (Forms, Queries, Reports) pull their data from tables."},hi:{q:"MS Access में डेटा संग्रहीत करने के लिए उपयोग किया जाने वाला मौलिक डेटाबेस ऑब्जेक्ट क्या है?",opts:["फ़ॉर्म (Form)","क्वेरी (Query)","टेबल (Table)","रिपोर्ट (Report)"],ans:2,exp:"'टेबल' (तालिका) MS Access सहित किसी भी डेटाबेस सिस्टम में मौलिक, मूलभूत ऑब्जेक्ट है। यह वास्तविक भंडारण कंटेनर है जहां कच्चे डेटा को पंक्तियों और स्तंभों के संरचित प्रारूप में भौतिक रूप से रखा जाता है। अन्य सभी डेटाबेस ऑब्जेक्ट (फ़ॉर्म, क्वेरी, रिपोर्ट) तालिकाओं से अपना डेटा खींचते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an example of a Relational Database Management System (RDBMS)?",opts:["MS Word","Notepad","MySQL","MS Paint"],ans:2,exp:"MySQL is a globally popular, open-source Relational Database Management System (RDBMS). It uses standard Structured Query Language (SQL) to manage and manipulate databases. MS Word, Notepad, and MS Paint are word processors, text editors, and image editors respectively, not database software."},hi:{q:"निम्नलिखित में से कौन सा रिलेशनल डेटाबेस मैनेजमेंट सिस्टम (RDBMS) का उदाहरण है?",opts:["MS Word","Notepad","MySQL","MS Paint"],ans:2,exp:"MySQL विश्व स्तर पर लोकप्रिय, ओपन-सोर्स रिलेशनल डेटाबेस मैनेजमेंट सिस्टम (RDBMS) है। यह डेटाबेस को प्रबंधित करने और हेरफेर करने के लिए मानक स्ट्रक्चर्ड क्वेरी लैंग्वेज (SQL) का उपयोग करता है। एमएस वर्ड, नोटपैड और एमएस पेंट क्रमशः वर्ड प्रोसेसर, टेक्स्ट एडिटर और इमेज एडिटर हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is a 'Primary Key' in a database table?",opts:["A key used to encrypt the database file","A field that uniquely identifies each record in a table","The first column of every database table","A password required to open the database"],ans:1,exp:"A Primary Key is a specialized field (or combination of fields) in a database table that uniquely identifies each individual record (row). It guarantees data integrity by strictly enforcing two rules: the primary key must contain a unique value for every row, and it cannot ever be left blank (NULL)."},hi:{q:"डेटाबेस तालिका में 'प्राइमरी की' (Primary Key) क्या है?",opts:["डेटाबेस फ़ाइल को एन्क्रिप्ट करने के लिए उपयोग की जाने वाली कुंजी","एक फ़ील्ड जो एक तालिका में प्रत्येक रिकॉर्ड की विशिष्ट रूप से पहचान करती है","प्रत्येक डेटाबेस तालिका का पहला कॉलम","डेटाबेस खोलने के लिए आवश्यक पासवर्ड"],ans:1,exp:"प्राइमरी की (Primary Key) एक डेटाबेस तालिका में एक विशेष फ़ील्ड है जो विशिष्ट रूप से प्रत्येक व्यक्तिगत रिकॉर्ड (पंक्ति) की पहचान करती है। यह दो नियमों को सख्ती से लागू करके डेटा अखंडता की गारंटी देता है: प्राइमरी की में हर पंक्ति के लिए एक अद्वितीय मूल्य होना चाहिए, और इसे कभी भी खाली (NULL) नहीं छोड़ा जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does SQL stand for?",opts:["Simple Question Language","Structured Query Language","System Query Logic","Sequential Query Language"],ans:1,exp:"SQL stands for Structured Query Language. It is the universally accepted, standard programming language specifically designed for communicating with relational databases. SQL is used to perform a wide variety of tasks, including retrieving data, updating records, creating tables, and managing user permissions."},hi:{q:"SQL का पूर्ण रूप क्या है?",opts:["सिंपल क्वेश्चन लैंग्वेज","स्ट्रक्चर्ड क्वेरी लैंग्वेज","सिस्टम क्वेरी लॉजिक","सीक्वेंशियल क्वेरी लैंग्वेज"],ans:1,exp:"SQL का पूर्ण रूप स्ट्रक्चर्ड क्वेरी लैंग्वेज है। यह विशेष रूप से रिलेशनल डेटाबेस के साथ संचार करने के लिए डिज़ाइन की गई सार्वभौमिक रूप से स्वीकृत, मानक प्रोग्रामिंग भाषा है। SQL का उपयोग डेटा पुनर्प्राप्त करने, रिकॉर्ड अपडेट करने, टेबल बनाने और अनुमतियों को प्रबंधित करने सहित कार्यों के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which database object is primarily used to ask questions and extract specific data from tables based on conditions?",opts:["Table","Form","Query","Report"],ans:2,exp:"A 'Query' is a powerful database object used to retrieve and process specific data from one or more tables based on defined conditions or criteria. Instead of viewing all raw data, a query filters, sorts, and extracts only the exact information the user is asking for, acting like a detailed search."},hi:{q:"शर्तों के आधार पर तालिकाओं से विशिष्ट डेटा निकालने और प्रश्न पूछने के लिए मुख्य रूप से किस डेटाबेस ऑब्जेक्ट का उपयोग किया जाता है?",opts:["टेबल (Table)","फ़ॉर्म (Form)","क्वेरी (Query)","रिपोर्ट (Report)"],ans:2,exp:"'क्वेरी' एक शक्तिशाली डेटाबेस ऑब्जेक्ट है जिसका उपयोग परिभाषित स्थितियों या मानदंडों के आधार पर एक या अधिक तालिकाओं से विशिष्ट डेटा को पुनः प्राप्त करने और संसाधित करने के लिए किया जाता है। सभी कच्चे डेटा को देखने के बजाय, एक क्वेरी एक विस्तृत खोज की तरह काम करते हुए केवल सटीक जानकारी निकालती है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the standard file extension for a modern Microsoft Access database (2007 and later)?",opts:[".mdb",".accdb",".dbf",".sql"],ans:1,exp:"Starting with MS Access 2007, Microsoft introduced the '.accdb' (Access Database) file format as the new default standard, replacing the older '.mdb' format. The .accdb format supports newer features like complex data types, multi-valued fields, improved encryption, and better integration with SharePoint."},hi:{q:"आधुनिक Microsoft Access डेटाबेस (2007 और बाद के) के लिए मानक फ़ाइल एक्सटेंशन क्या है?",opts:[".mdb",".accdb",".dbf",".sql"],ans:1,exp:"MS Access 2007 से शुरू होकर, Microsoft ने पुराने '.mdb' प्रारूप को प्रतिस्थापित करते हुए, नए डिफ़ॉल्ट मानक के रूप में '.accdb' (एक्सेस डेटाबेस) फ़ाइल स्वरूप पेश किया। .accdb प्रारूप जटिल डेटा प्रकार, बहु-मूल्यवान फ़ील्ड, बेहतर एन्क्रिप्शन और शेयरपॉइंट के साथ बेहतर एकीकरण जैसी नई सुविधाओं का समर्थन करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which database object is designed to provide a user-friendly, graphical interface for entering and viewing data?",opts:["Query","Macro","Report","Form"],ans:3,exp:"A 'Form' provides a structured, graphical User Interface (UI) that makes it easy for end-users to enter new records, modify existing data, or view table data one record at a time. Forms hide the complex, raw table grid, reducing data entry errors and providing buttons for easy navigation."},hi:{q:"डेटा दर्ज करने और देखने के लिए उपयोगकर्ता के अनुकूल, ग्राफिकल इंटरफ़ेस प्रदान करने के लिए कौन सा डेटाबेस ऑब्जेक्ट डिज़ाइन किया गया है?",opts:["क्वेरी (Query)","मैक्रो (Macro)","रिपोर्ट (Report)","फ़ॉर्म (Form)"],ans:3,exp:"'फ़ॉर्म' एक संरचित, ग्राफिकल यूजर इंटरफेस (UI) प्रदान करता है जो अंतिम उपयोगकर्ताओं के लिए नए रिकॉर्ड दर्ज करना, मौजूदा डेटा को संशोधित करना या एक बार में टेबल डेटा देखना आसान बनाता है। प्रपत्र जटिल, कच्चे टेबल ग्रिड को छिपाते हैं, डेटा प्रविष्टि त्रुटियों को कम करते हैं और आसान नेविगेशन के लिए बटन प्रदान करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the purpose of a 'Report' in MS Access?",opts:["To permanently delete corrupted records","To input new data into the database rapidly","To format, summarize, and present data for printing or professional sharing","To design the internal schema of a table"],ans:2,exp:"A 'Report' is specifically engineered to organize, summarize, and format database information into a visually appealing layout suitable for printing, exporting as a PDF, or presenting in meetings. Unlike forms which are for data entry, reports are strictly read-only outputs of processed data."},hi:{q:"MS Access में 'रिपोर्ट' (Report) का उद्देश्य क्या है?",opts:["भ्रष्ट रिकॉर्ड को स्थायी रूप से हटाने के लिए","तेजी से डेटाबेस में नया डेटा इनपुट करने के लिए","प्रिंटिंग या पेशेवर साझाकरण के लिए डेटा को प्रारूपित, सारांशित और प्रस्तुत करने के लिए","तालिका के आंतरिक स्कीमा को डिजाइन करने के लिए"],ans:2,exp:"एक 'रिपोर्ट' विशेष रूप से मुद्रण, पीडीएफ के रूप में निर्यात करने या बैठकों में प्रस्तुत करने के लिए उपयुक्त एक आकर्षक लेआउट में डेटाबेस जानकारी को व्यवस्थित, सारांशित और प्रारूपित करने के लिए इंजीनियर है। प्रपत्रों के विपरीत जो डेटा प्रविष्टि के लिए होते हैं, रिपोर्ट सख्ती से संसाधित डेटा के केवल-पढ़ने के लिए आउटपुट होते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"In a database, what is an 'Attribute' commonly known as?",opts:["Row","Table","Column or Field","Database File"],ans:2,exp:"In relational database theory, an 'Attribute' refers to a property or characteristic of an entity. In practical software like MS Access or MySQL, an attribute is physically represented as a 'Column' or 'Field'. For example, in an Employee table, 'FirstName' and 'Salary' are distinct attributes or fields."},hi:{q:"डेटाबेस में, 'एट्रीब्यूट' (Attribute) को आमतौर पर किस रूप में जाना जाता है?",opts:["रो (Row)","टेबल (Table)","कॉलम या फ़ील्ड (Column or Field)","डेटाबेस फ़ाइल (Database File)"],ans:2,exp:"संबंधपरक डेटाबेस सिद्धांत में, एक 'एट्रीब्यूट' एक इकाई की संपत्ति या विशेषता को संदर्भित करता है। व्यावहारिक सॉफ़्टवेयर जैसे MS Access या MySQL में, एक विशेषता को भौतिक रूप से 'कॉलम' या 'फ़ील्ड' के रूप में दर्शाया जाता है। उदाहरण के लिए, कर्मचारी तालिका में, 'FirstName' और 'Salary' अलग-अलग विशेषताएं हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following data types in MS Access is most appropriate for storing a person's first name?",opts:["Number","Short Text","Date/Time","Currency"],ans:1,exp:"The 'Short Text' (previously known as Text) data type is specifically designed to store alphanumeric characters—letters, numbers, and symbols—up to a maximum of 255 characters. It is the perfect and most memory-efficient choice for storing brief string data like names, addresses, or phone numbers."},hi:{q:"MS Access में निम्नलिखित में से कौन सा डेटा प्रकार किसी व्यक्ति का पहला नाम संग्रहीत करने के लिए सबसे उपयुक्त है?",opts:["Number","Short Text","Date/Time","Currency"],ans:1,exp:"'शॉर्ट टेक्स्ट' (Short Text) डेटा प्रकार विशेष रूप से अधिकतम 255 वर्णों तक अल्फ़ान्यूमेरिक वर्णों—अक्षर, संख्या और प्रतीकों—को संग्रहीत करने के लिए डिज़ाइन किया गया है। यह नाम, पते या फोन नंबर जैसे संक्षिप्त स्ट्रिंग डेटा को संग्रहीत करने के लिए एकदम सही और सबसे मेमोरी-कुशल विकल्प है।"}},
{type:"mcq",diff:"easy",en:{q:"Which basic SQL command is used to retrieve data from a database?",opts:["PULL","GET","SELECT","FETCH"],ans:2,exp:"The 'SELECT' command is the most foundational and frequently used statement in SQL. It is responsible for querying the database and retrieving specific rows and columns of data from one or more tables, returning the results in a temporary structure known as a result-set."},hi:{q:"डेटाबेस से डेटा प्राप्त करने के लिए किस मूल SQL कमांड का उपयोग किया जाता है?",opts:["PULL","GET","SELECT","FETCH"],ans:2,exp:"'SELECT' कमांड SQL में सबसे मूलभूत और अक्सर उपयोग किया जाने वाला कथन है। यह डेटाबेस को क्वेरी करने और एक या अधिक तालिकाओं से डेटा की विशिष्ट पंक्तियों और स्तंभों को पुनर्प्राप्त करने के लिए जिम्मेदार है, जिससे परिणाम-सेट के रूप में जाना जाने वाला एक अस्थायी संरचना में परिणाम वापस आ जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which SQL command is used to add brand new rows of data into an existing table?",opts:["ADD RECORD","INSERT INTO","NEW ROW","APPEND DATA"],ans:1,exp:"The 'INSERT INTO' SQL command is utilized to add new, complete records (rows) into a designated database table. The syntax requires specifying the table name, the specific columns to receive data, and the exact corresponding values to be inserted into those columns."},hi:{q:"मौजूदा तालिका में डेटा की नई पंक्तियाँ जोड़ने के लिए किस SQL कमांड का उपयोग किया जाता है?",opts:["ADD RECORD","INSERT INTO","NEW ROW","APPEND DATA"],ans:1,exp:"'INSERT INTO' SQL कमांड का उपयोग निर्दिष्ट डेटाबेस तालिका में नए, पूर्ण रिकॉर्ड (पंक्तियों) को जोड़ने के लिए किया जाता है। सिंटैक्स के लिए तालिका नाम, डेटा प्राप्त करने के लिए विशिष्ट कॉलम और उन कॉलम में सम्मिलित किए जाने वाले सटीक संबंधित मानों को निर्दिष्ट करने की आवश्यकता होती है।"}},
{type:"mcq",diff:"easy",en:{q:"What does DML stand for in database terminology?",opts:["Data Manipulation Language","Database Management Logic","Digital Marking Language","Data Modification Level"],ans:0,exp:"DML stands for Data Manipulation Language. It is a sub-language of SQL that consists of commands primarily used for adding, updating, modifying, and deleting actual data stored inside the database tables. The core DML commands are INSERT, UPDATE, and DELETE."},hi:{q:"डेटाबेस शब्दावली में DML का पूर्ण रूप क्या है?",opts:["डेटा मैनिपुलेशन लैंग्वेज","डेटाबेस मैनेजमेंट लॉजिक","डिजिटल मार्किंग लैंग्वेज","डेटा मॉडिफिकेशन लेवल"],ans:0,exp:"DML का अर्थ डेटा मैनिपुलेशन लैंग्वेज है। यह SQL की एक उप-भाषा है जिसमें मुख्य रूप से डेटाबेस तालिकाओं के अंदर संग्रहीत वास्तविक डेटा को जोड़ने, अद्यतन करने, संशोधित करने और हटाने के लिए उपयोग किए जाने वाले आदेश शामिल हैं। मुख्य DML कमांड INSERT, UPDATE और DELETE हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does DDL stand for?",opts:["Data Deletion Language","Data Definition Language","Database Design Logic","Data Dictionary Language"],ans:1,exp:"DDL stands for Data Definition Language. It comprises SQL commands used strictly to define, modify, or destroy the structural schema and architectural objects of the database itself, such as tables, indexes, and views. Key DDL commands include CREATE, ALTER, and DROP."},hi:{q:"DDL का पूर्ण रूप क्या है?",opts:["डेटा डिलीशन लैंग्वेज","डेटा डेफिनिशन लैंग्वेज","डेटाबेस डिज़ाइन लॉजिक","डेटा डिक्शनरी लैंग्वेज"],ans:1,exp:"DDL का अर्थ डेटा डेफिनिशन लैंग्वेज है। इसमें SQL कमांड शामिल हैं जिनका उपयोग डेटाबेस के संरचनात्मक स्कीमा और वास्तुशिल्प वस्तुओं, जैसे टेबल और इंडेक्स को परिभाषित करने, संशोधित करने या नष्ट करने के लिए किया जाता है। प्रमुख DDL कमांड में CREATE, ALTER और DROP शामिल हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which wildcard character is used in a SELECT statement to choose ALL columns from a table?",opts:["% (Percent)","? (Question Mark)","* (Asterisk)","# (Hash)"],ans:2,exp:"In standard SQL syntax, the asterisk (*) is used as a powerful wildcard in the SELECT clause. Writing 'SELECT * FROM TableName' commands the database engine to retrieve and display every single column available in that table, saving the user from manually typing out every column name."},hi:{q:"एक तालिका से सभी कॉलम चुनने के लिए SELECT कथन में किस वाइल्डकार्ड वर्ण का उपयोग किया जाता है?",opts:["% (प्रतिशत)","? (प्रश्न चिह्न)","* (तारांकन / Asterisk)","# (हैश)"],ans:2,exp:"मानक SQL सिंटैक्स में, SELECT क्लॉज में तारांकन (*) का उपयोग एक शक्तिशाली वाइल्डकार्ड के रूप में किया जाता है। 'SELECT * FROM TableName' लिखने से डेटाबेस इंजन उस तालिका में उपलब्ध हर एक कॉलम को पुनः प्राप्त करने और प्रदर्शित करने का आदेश देता है, जिससे उपयोगकर्ता हर कॉलम नाम टाइप करने से बच जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which SQL command allows you to change or modify existing data within a table?",opts:["MODIFY","CHANGE","ALTER","UPDATE"],ans:3,exp:"The 'UPDATE' command is the standard DML statement used to modify existing data records currently residing in a table. It is almost always used in conjunction with a WHERE clause to precisely target which specific rows should be updated, preventing accidental mass data changes."},hi:{q:"कौन सा SQL कमांड आपको एक तालिका के भीतर मौजूदा डेटा को बदलने या संशोधित करने की अनुमति देता है?",opts:["MODIFY","CHANGE","ALTER","UPDATE"],ans:3,exp:"'UPDATE' कमांड मानक DML स्टेटमेंट है जिसका उपयोग तालिका में वर्तमान में मौजूद मौजूदा डेटा रिकॉर्ड को संशोधित करने के लिए किया जाता है। इसका उपयोग लगभग हमेशा एक WHERE क्लॉज के साथ किया जाता है ताकि यह सटीक रूप से लक्षित किया जा सके कि किन विशिष्ट पंक्तियों को अपडेट किया जाना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"Which SQL command permanently removes a record (row) from a table?",opts:["REMOVE","DELETE","DROP","ERASE"],ans:1,exp:"The 'DELETE' command is used to permanently eliminate existing rows of data from a table. Like UPDATE, the DELETE command should be strictly controlled with a WHERE clause to specify exactly which record to remove. Executing DELETE without a WHERE clause will erase all records in the table."},hi:{q:"कौन सा SQL कमांड किसी टेबल से स्थायी रूप से रिकॉर्ड (पंक्ति) को हटा देता है?",opts:["REMOVE","DELETE","DROP","ERASE"],ans:1,exp:"'DELETE' कमांड का उपयोग टेबल से डेटा की मौजूदा पंक्तियों को स्थायी रूप से समाप्त करने के लिए किया जाता है। अद्यतन की तरह, ठीक से निर्दिष्ट करने के लिए कि किस रिकॉर्ड को हटाना है, DELETE कमांड को WHERE क्लॉज के साथ कड़ाई से नियंत्रित किया जाना चाहिए। इसके बिना तालिका के सभी रिकॉर्ड मिट जाएंगे।"}},
{type:"mcq",diff:"easy",en:{q:"What is the function of a 'Foreign Key'?",opts:["To automatically generate random passwords","To link two tables together by referencing the Primary Key of another table","To encrypt data being transmitted over a network","To sort data in descending order"],ans:1,exp:"A Foreign Key is a field in one relational table that exactly matches the Primary Key column of another related table. Its sole function is to establish and enforce a hard link (referential integrity) between the data in the two tables, preventing orphan records and ensuring relational consistency."},hi:{q:"'फॉरेन की' (Foreign Key) का क्या कार्य है?",opts:["स्वचालित रूप से यादृच्छिक पासवर्ड उत्पन्न करने के लिए","किसी अन्य तालिका की प्राइमरी की को संदर्भित करके दो तालिकाओं को एक साथ जोड़ने के लिए","नेटवर्क पर प्रेषित किए जा रहे डेटा को एन्क्रिप्ट करने के लिए","डेटा को अवरोही क्रम में क्रमबद्ध करने के लिए"],ans:1,exp:"फॉरेन की एक रिलेशनल टेबल में एक फ़ील्ड है जो किसी अन्य संबंधित टेबल के प्राइमरी की कॉलम से बिल्कुल मेल खाती है। इसका एकमात्र कार्य अनाथ रिकॉर्ड (orphan records) को रोकने और संबंधपरक स्थिरता सुनिश्चित करने के लिए दो तालिकाओं में डेटा के बीच एक हार्ड लिंक स्थापित करना और लागू करना है।"}},
{type:"mcq",diff:"easy",en:{q:"In MS Access, which View provides the tools necessary to create fields, set data types, and define the table's structural schema?",opts:["Datasheet View","Design View","Layout View","Print Preview"],ans:1,exp:"'Design View' is the architectural interface in MS Access used by database builders. It does not display the actual data. Instead, it allows the user to meticulously define the structural blueprints of a table: creating column names, setting specific data types, assigning primary keys, and establishing field properties."},hi:{q:"MS Access में, कौन सा दृश्य (View) फ़ील्ड बनाने, डेटा प्रकार सेट करने और तालिका के संरचनात्मक स्कीमा को परिभाषित करने के लिए आवश्यक उपकरण प्रदान करता है?",opts:["डेटाशीट व्यू (Datasheet View)","डिज़ाइन व्यू (Design View)","लेआउट व्यू (Layout View)","प्रिंट प्रिव्यू (Print Preview)"],ans:1,exp:"'डिज़ाइन व्यू' MS Access में वास्तुशिल्प इंटरफ़ेस है जिसका उपयोग डेटाबेस बिल्डरों द्वारा किया जाता है। यह वास्तविक डेटा प्रदर्शित नहीं करता है। इसके बजाय, यह उपयोगकर्ता को तालिका के संरचनात्मक ब्लूप्रिंट को सावधानीपूर्वक परिभाषित करने की अनुमति देता है: कॉलम नाम बनाना, डेटा प्रकार सेट करना और प्राइमरी की असाइन करना।"}},
{type:"mcq",diff:"easy",en:{q:"Which MS Access View looks similar to an Excel spreadsheet and is used for direct data entry?",opts:["Design View","SQL View","Datasheet View","Report View"],ans:2,exp:"'Datasheet View' visually represents the table as a simple grid of rows and columns, heavily resembling an MS Excel spreadsheet. This view is exclusively meant for operational data entry, allowing users to manually type, edit, delete, and scroll through the actual raw records stored in the database."},hi:{q:"कौन सा MS Access दृश्य Excel स्प्रेडशीट के समान दिखता है और सीधे डेटा प्रविष्टि के लिए उपयोग किया जाता है?",opts:["डिज़ाइन व्यू (Design View)","SQL व्यू (SQL View)","डेटाशीट व्यू (Datasheet View)","रिपोर्ट व्यू (Report View)"],ans:2,exp:"'डेटाशीट व्यू' तालिका को पंक्तियों और स्तंभों के एक साधारण ग्रिड के रूप में प्रदर्शित करता है, जो एमएस एक्सेल स्प्रेडशीट के समान है। यह दृश्य विशेष रूप से परिचालन डेटा प्रविष्टि के लिए है, जिससे उपयोगकर्ता डेटाबेस में संग्रहीत वास्तविक कच्चे रिकॉर्ड को मैन्युअल रूप से टाइप, संपादित और हटा सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the maximum number of characters that a 'Short Text' data type can hold in MS Access?",opts:["50","100","255","65535"],ans:2,exp:"In MS Access, the 'Short Text' data type has a hard system limitation; it can store a maximum of exactly 255 alphanumeric characters. If a user needs to store large paragraphs, product descriptions, or extensive notes exceeding 255 characters, they must use the 'Long Text' (Memo) data type instead."},hi:{q:"MS Access में 'शॉर्ट टेक्स्ट' डेटा प्रकार अधिकतम कितने वर्ण (characters) रख सकता है?",opts:["50","100","255","65535"],ans:2,exp:"MS Access में, 'शॉर्ट टेक्स्ट' डेटा प्रकार की एक कठिन सिस्टम सीमा होती है; यह अधिकतम 255 अल्फ़ान्यूमेरिक वर्णों को संग्रहीत कर सकता है। यदि किसी उपयोगकर्ता को 255 वर्णों से अधिक बड़े पैराग्राफ, उत्पाद विवरण या व्यापक नोट संग्रहीत करने की आवश्यकता है, तो उन्हें 'लॉन्ग टेक्स्ट' (मेमो) डेटा प्रकार का उपयोग करना चाहिए।"}},
{type:"mcq",diff:"easy",en:{q:"Which MS Access data type is specifically designed to store monetary values and prevents rounding errors during calculations?",opts:["Number","Currency","Double","AutoNumber"],ans:1,exp:"The 'Currency' data type is engineered specifically for financial data. Unlike standard floating-point Number types which can suffer from minute rounding errors in complex mathematics, Currency uses fixed-point math to maintain absolute precision up to four decimal places, ensuring financial reports remain perfectly accurate."},hi:{q:"कौन सा MS Access डेटा प्रकार विशेष रूप से मौद्रिक मूल्यों को संग्रहीत करने के लिए डिज़ाइन किया गया है और गणना के दौरान गोलाई (rounding) त्रुटियों को रोकता है?",opts:["Number","Currency","Double","AutoNumber"],ans:1,exp:"'करेंसी' (Currency) डेटा प्रकार विशेष रूप से वित्तीय डेटा के लिए इंजीनियर है। मानक फ़्लोटिंग-पॉइंट नंबर प्रकारों के विपरीत जो जटिल गणित में मामूली त्रुटियों का सामना कर सकते हैं, करेंसी चार दशमलव स्थानों तक पूर्ण सटीकता बनाए रखने के लिए निश्चित-बिंदु गणित का उपयोग करती है, यह सुनिश्चित करती है कि वित्तीय रिपोर्ट सटीक रहें।"}},
{type:"mcq",diff:"easy",en:{q:"Which data type in Access is best suited for a field like 'Is Active Employee?' requiring only a True or False answer?",opts:["Short Text","Number","Yes/No","Lookup Wizard"],ans:2,exp:"The 'Yes/No' data type is a boolean logic field. It is highly optimized to store binary data states, representing only one of two possible values: Yes/No, True/False, or On/Off. In the Access GUI, it is typically displayed as a clickable checkbox, making data entry incredibly fast and standardized."},hi:{q:"Access में कौन सा डेटा प्रकार 'क्या सक्रिय कर्मचारी है?' (Is Active Employee) जैसे क्षेत्र के लिए सबसे उपयुक्त है, जिसमें केवल सही या गलत उत्तर की आवश्यकता होती है?",opts:["Short Text","Number","Yes/No","Lookup Wizard"],ans:2,exp:"'यस/नो' (Yes/No) डेटा प्रकार एक बूलियन लॉजिक फील्ड है। यह द्विआधारी डेटा राज्यों को संग्रहीत करने के लिए अत्यधिक अनुकूलित है, दो संभावित मानों में से केवल एक का प्रतिनिधित्व करता है: हां/नहीं, सही/गलत, या चालू/बंद। एक्सेस जीयूआई में, इसे आम तौर पर क्लिक करने योग्य चेकबॉक्स के रूप में प्रदर्शित किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a Database Schema?",opts:["A software patch for MS Access","The logical design, structure, and blueprint of the entire database","A specific SQL command to extract data","A type of network protocol"],ans:1,exp:"A database schema is the overarching architectural blueprint of the database. It formally defines how data is organized, detailing the tables, the specific fields within those tables, the data types, the constraints, and the complex relational links between the different tables that make up the system."},hi:{q:"डेटाबेस स्कीमा क्या है?",opts:["MS Access के लिए एक सॉफ्टवेयर पैच","संपूर्ण डेटाबेस का तार्किक डिज़ाइन, संरचना और ब्लूप्रिंट","डेटा निकालने के लिए एक विशिष्ट SQL कमांड","एक प्रकार का नेटवर्क प्रोटोकॉल"],ans:1,exp:"डेटाबेस स्कीमा डेटाबेस का व्यापक वास्तुशिल्प ब्लूप्रिंट है। यह औपचारिक रूप से परिभाषित करता है कि डेटा कैसे व्यवस्थित किया जाता है, तालिकाओं का विवरण, उन तालिकाओं के भीतर विशिष्ट फ़ील्ड, डेटा प्रकार, बाधाएं और विभिन्न तालिकाओं के बीच जटिल संबंधपरक लिंक जो सिस्टम बनाते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which clause in SQL is used to filter records and extract only those that fulfill a specified condition?",opts:["ORDER BY","GROUP BY","WHERE","SORT"],ans:2,exp:"The 'WHERE' clause is the fundamental filtering mechanism in SQL. It is appended to SELECT, UPDATE, or DELETE statements to restrict operations. The database engine evaluates the logical condition in the WHERE clause (e.g., WHERE Salary > 50000) and strictly returns or affects only the rows where the condition is TRUE."},hi:{q:"SQL में किस क्लॉज का उपयोग रिकॉर्ड को फ़िल्टर करने और केवल उन लोगों को निकालने के लिए किया जाता है जो निर्दिष्ट शर्त को पूरा करते हैं?",opts:["ORDER BY","GROUP BY","WHERE","SORT"],ans:2,exp:"'WHERE' क्लॉज SQL में मौलिक फ़िल्टरिंग तंत्र है। यह संचालन को प्रतिबंधित करने के लिए SELECT, UPDATE, या DELETE कथनों से जुड़ा हुआ है। डेटाबेस इंजन WHERE क्लॉज में तार्किक स्थिति का मूल्यांकन करता है (उदा., WHERE Salary > 50000) और कड़ाई से केवल उन पंक्तियों को लौटाता है जहां स्थिति सत्य है।"}},
// EASY - TRUE/FALSE (2 Questions)
{type:"tf",diff:"easy",en:{q:"A Primary Key column is allowed to contain NULL (blank) values as long as the other values are unique.",opts:["True","False"],ans:1,exp:"False. The most critical rule of Entity Integrity dictates that a Primary Key must uniquely identify a record, and therefore it can NEVER be NULL. If a primary key were left blank, the database engine would physically lose the ability to uniquely track and reference that specific row."},hi:{q:"एक प्राइमरी की (Primary Key) कॉलम में शून्य (रिक्त) मान (NULL values) शामिल करने की अनुमति है जब तक कि अन्य मान अद्वितीय हों।",opts:["सही","गलत"],ans:1,exp:"गलत। एंटिटी इंटीग्रिटी का सबसे महत्वपूर्ण नियम यह निर्देश देता है कि एक प्राइमरी की विशिष्ट रूप से एक रिकॉर्ड की पहचान करनी चाहिए, और इसलिए यह कभी भी शून्य (NULL) नहीं हो सकती है। यदि इसे खाली छोड़ दिया जाता है, तो डेटाबेस इंजन भौतिक रूप से उस विशिष्ट पंक्ति को ट्रैक करने की क्षमता खो देगा।"}},
{type:"tf",diff:"easy",en:{q:"Microsoft Access is classified as a Relational Database Management System (RDBMS).",opts:["True","False"],ans:0,exp:"True. MS Access is fundamentally an RDBMS. It provides all the necessary tools to create multiple distinct data tables, establish primary and foreign keys, and logically link those tables together using relational joins, allowing users to query data seamlessly across the entire database."},hi:{q:"Microsoft Access को रिलेशनल डेटाबेस मैनेजमेंट सिस्टम (RDBMS) के रूप में वर्गीकृत किया गया है।",opts:["सही","गलत"],ans:0,exp:"सही। MS Access मौलिक रूप से एक RDBMS है। यह कई अलग-अलग डेटा टेबल बनाने, प्राथमिक और विदेशी कुंजी स्थापित करने और उन तालिकाओं को तार्किक रूप से एक साथ जोड़ने के लिए आवश्यक सभी उपकरण प्रदान करता है, जिससे उपयोगकर्ता पूरे डेटाबेस में निर्बाध रूप से डेटा क्वेरी कर सकते हैं।"}},

// MEDIUM - MCQ (28 Questions)
{type:"mcq",diff:"medium",en:{q:"Which MS Access data type is utilized for storing massive amounts of text, such as detailed product descriptions exceeding 255 characters?",opts:["Short Text","Long Text (Memo)","Hyperlink","Attachment"],ans:1,exp:"The 'Long Text' data type (formerly known historically as 'Memo') is designed to bypass the 255-character limit of Short Text. It can comfortably store massive blocks of alphanumeric data, technically capable of holding up to 65,535 characters, making it ideal for robust notes, essays, or detailed logs."},hi:{q:"255 वर्णों से अधिक विस्तृत उत्पाद विवरण जैसे भारी मात्रा में पाठ संग्रहीत करने के लिए किस MS Access डेटा प्रकार का उपयोग किया जाता है?",opts:["Short Text","Long Text (Memo)","Hyperlink","Attachment"],ans:1,exp:"'लॉन्ग टेक्स्ट' डेटा प्रकार (जिसे पहले 'मेमो' के रूप में जाना जाता था) को शॉर्ट टेक्स्ट की 255-वर्ण सीमा को बायपास करने के लिए डिज़ाइन किया गया है। यह आसानी से अल्फ़ान्यूमेरिक डेटा के विशाल ब्लॉकों को संग्रहीत कर सकता है, तकनीकी रूप से 65,535 वर्णों तक रखने में सक्षम है, जो इसे विस्तृत लॉग के लिए आदर्श बनाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary function of the 'OLE Object' data type in older versions of MS Access?",opts:["To create Object-Oriented programming code","To store automated macros","To embed external files like Word documents, Excel spreadsheets, or images directly into a table record","To generate random numerical keys"],ans:2,exp:"'OLE' stands for Object Linking and Embedding. This legacy data type allows users to physically embed or link entire external files—such as an MS Excel worksheet, a complex graphic, or an MS Word document—directly into a database cell, though it severely inflates the database file size."},hi:{q:"MS Access के पुराने संस्करणों में 'OLE Object' डेटा प्रकार का प्राथमिक कार्य क्या है?",opts:["ऑब्जेक्ट-ओरिएंटेड प्रोग्रामिंग कोड बनाने के लिए","स्वचालित मैक्रोज़ को संग्रहीत करने के लिए","वर्ड डॉक्यूमेंट, एक्सेल स्प्रेडशीट या इमेज जैसी बाहरी फाइलों को सीधे टेबल रिकॉर्ड में एम्बेड करने के लिए","यादृच्छिक संख्यात्मक कुंजियाँ उत्पन्न करने के लिए"],ans:2,exp:"'OLE' का अर्थ है ऑब्जेक्ट लिंकिंग और एम्बेडिंग। यह लीगेसी डेटा प्रकार उपयोगकर्ताओं को भौतिक रूप से एम्बेड करने या संपूर्ण बाहरी फ़ाइलों को लिंक करने की अनुमति देता है - जैसे कि MS Excel वर्कशीट, एक ग्राफ़िक, या MS Word दस्तावेज़ - सीधे डेटाबेस सेल में, हालाँकि यह डेटाबेस फ़ाइल के आकार को गंभीर रूप से बढ़ाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which data type automatically generates a unique sequential or random numeric value whenever a new record is added to the table?",opts:["Number","Calculated","AutoNumber","Lookup"],ans:2,exp:"The 'AutoNumber' data type is a system-controlled field. When designated, Access automatically inserts a unique sequential integer (1, 2, 3...) or a random number the exact moment a new row is created. Because it guarantees uniqueness and cannot be manually edited, it is universally used as a Primary Key."},hi:{q:"तालिका में नया रिकॉर्ड जोड़े जाने पर कौन सा डेटा प्रकार स्वचालित रूप से एक अद्वितीय अनुक्रमिक (sequential) या यादृच्छिक संख्यात्मक मान उत्पन्न करता है?",opts:["Number","Calculated","AutoNumber","Lookup"],ans:2,exp:"'ऑटोनंबर' (AutoNumber) डेटा प्रकार एक सिस्टम-नियंत्रित क्षेत्र है। जब नामित किया जाता है, तो एक नई पंक्ति बनाए जाने पर एक्सेस स्वचालित रूप से एक अद्वितीय अनुक्रमिक पूर्णांक (1, 2, 3...) या एक यादृच्छिक संख्या सम्मिलित करता है। क्योंकि यह विशिष्टता की गारंटी देता है, इसे सार्वभौमिक रूप से प्राथमिक कुंजी के रूप में उपयोग किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"When linking two tables, what does enforcing 'Referential Integrity' ensure?",opts:["It ensures passwords are secure","It ensures the database runs faster","It prevents the creation of orphan records by ensuring a foreign key value must have a matching primary key value in the related table","It ensures all text is in uppercase"],ans:2,exp:"'Referential Integrity' is a critical set of logical rules. When enforced on a relationship, the database strictly prevents users from adding a foreign key value if that value doesn't already exist in the primary table. It also prevents deleting a parent record if child records still depend on it, halting data corruption."},hi:{q:"दो तालिकाओं को जोड़ते समय, 'रेफरेंशियल इंटीग्रिटी' (Referential Integrity) को लागू करना क्या सुनिश्चित करता है?",opts:["यह सुनिश्चित करता है कि पासवर्ड सुरक्षित हैं","यह सुनिश्चित करता है कि डेटाबेस तेजी से चलता है","यह सुनिश्चित करके अनाथ (orphan) रिकॉर्ड के निर्माण को रोकता है कि एक विदेशी कुंजी (foreign key) मान में संबंधित तालिका में एक मिलान प्राथमिक कुंजी मान होना चाहिए","यह सुनिश्चित करता है कि सभी टेक्स्ट अपरकेस में हों"],ans:2,exp:"'रेफरेंशियल इंटीग्रिटी' तार्किक नियमों का एक महत्वपूर्ण समूह है। जब लागू किया जाता है, तो डेटाबेस उपयोगकर्ताओं को एक विदेशी कुंजी मान जोड़ने से सख्ती से रोकता है यदि वह मान प्राथमिक तालिका में पहले से मौजूद नहीं है। यह माता-पिता के रिकॉर्ड को हटाने से भी रोकता है यदि बाल रिकॉर्ड अभी भी इस पर निर्भर हैं, डेटा भ्रष्टाचार को रोकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is the most common type of relationship found in a relational database?",opts:["One-to-One","One-to-Many","Many-to-Many","Zero-to-Many"],ans:1,exp:"The 'One-to-Many' (1:M) relationship is the backbone of relational design. It occurs when a single record in Table A can be associated with multiple records in Table B, but a record in Table B belongs to only one record in Table A. Example: One 'Customer' can place Many 'Orders'."},hi:{q:"रिलेशनल डेटाबेस में पाया जाने वाला सबसे सामान्य प्रकार का संबंध निम्नलिखित में से कौन सा है?",opts:["वन-टू-वन (One-to-One)","वन-टू-मैनी (One-to-Many)","मैनी-टू-मैनी (Many-to-Many)","जीरो-टू-मैनी (Zero-to-Many)"],ans:1,exp:"'वन-टू-मैनी' (1:M) संबंध रिलेशनल डिज़ाइन की रीढ़ है। यह तब होता है जब तालिका A में एकल रिकॉर्ड तालिका B में कई रिकॉर्ड से जुड़ा हो सकता है, लेकिन तालिका B में एक रिकॉर्ड तालिका A में केवल एक रिकॉर्ड का है। उदाहरण: एक 'ग्राहक' कई 'आदेश' (orders) दे सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"To properly establish a Many-to-Many relationship between two tables, what structural architectural component must be introduced?",opts:["A Macro","A Junction Table (Intermediary Table)","A Report","A calculated field"],ans:1,exp:"Relational databases cannot physically resolve direct Many-to-Many relationships. To implement this logically, a third table called a 'Junction Table' (or associative entity) must be created. It sits between the two main tables and holds foreign keys referencing the primary keys of both, breaking the Many-to-Many into two One-to-Many relationships."},hi:{q:"दो तालिकाओं के बीच 'मैनी-टू-मैनी' संबंध को ठीक से स्थापित करने के लिए, किस संरचनात्मक वास्तुशिल्प घटक को पेश किया जाना चाहिए?",opts:["एक मैक्रो (A Macro)","एक जंक्शन टेबल (A Junction Table)","एक रिपोर्ट (A Report)","एक परिकलित क्षेत्र (A calculated field)"],ans:1,exp:"रिलेशनल डेटाबेस भौतिक रूप से प्रत्यक्ष 'मैनी-टू-मैनी' संबंधों को हल नहीं कर सकते हैं। इसे लागू करने के लिए, 'जंक्शन टेबल' नामक एक तीसरी तालिका बनाई जानी चाहिए। यह दो मुख्य तालिकाओं के बीच बैठता है और दोनों की प्राथमिक कुंजियों को संदर्भित करने वाली विदेशी कुंजियाँ रखता है, जो इसे दो 'वन-टू-मैनी' संबंधों में तोड़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which SQL clause is used to sort the result-set retrieved by a SELECT statement?",opts:["SORT BY","GROUP BY","ORDER BY","ARRANGE BY"],ans:2,exp:"The 'ORDER BY' clause is universally used in SQL to alphabetically or numerically sort the output records of a SELECT query. By designating specific columns in the ORDER BY clause, the database engine organizes the final result-set, making large datasets readable and structurally organized."},hi:{q:"SELECT स्टेटमेंट द्वारा प्राप्त परिणाम-सेट (result-set) को सॉर्ट करने के लिए किस SQL क्लॉज का उपयोग किया जाता है?",opts:["SORT BY","GROUP BY","ORDER BY","ARRANGE BY"],ans:2,exp:"'ORDER BY' क्लॉज का उपयोग सार्वभौमिक रूप से SQL में SELECT क्वेरी के आउटपुट रिकॉर्ड को वर्णानुक्रम या संख्यात्मक रूप से सॉर्ट करने के लिए किया जाता है। ORDER BY क्लॉज में विशिष्ट कॉलम निर्दिष्ट करके, डेटाबेस इंजन अंतिम परिणाम-सेट को व्यवस्थित करता है, जिससे बड़े डेटासेट पठनीय हो जाते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"If the ORDER BY clause is used without explicitly specifying ASC or DESC, what is the default sorting behavior?",opts:["Descending (Z-A, 9-0)","Random order","Ascending (A-Z, 0-9)","It throws a syntax error"],ans:2,exp:"By default engineering design, if a user appends an 'ORDER BY column_name' clause to a query without adding a directional keyword, the SQL engine will automatically sort the data in Ascending order (lowest to highest, A to Z). To reverse this, the 'DESC' keyword must be explicitly typed."},hi:{q:"यदि ASC या DESC को स्पष्ट रूप से निर्दिष्ट किए बिना ORDER BY क्लॉज का उपयोग किया जाता है, तो डिफ़ॉल्ट सॉर्टिंग व्यवहार क्या है?",opts:["अवरोही (Z-A, 9-0)","यादृच्छिक क्रम (Random order)","आरोही (A-Z, 0-9)","यह एक सिंटैक्स त्रुटि देता है"],ans:2,exp:"डिफ़ॉल्ट इंजीनियरिंग डिज़ाइन द्वारा, यदि कोई उपयोगकर्ता दिशात्मक कीवर्ड जोड़े बिना क्वेरी में 'ORDER BY' क्लॉज जोड़ता है, तो SQL इंजन स्वचालित रूप से आरोही क्रम (निम्नतम से उच्चतम, A से Z) में डेटा को सॉर्ट करेगा। इसे उलटने के लिए, 'DESC' कीवर्ड स्पष्ट रूप से टाइप किया जाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"Which SQL clause is required to group rows that have the same values into summary rows, typically used alongside aggregate functions like SUM() or COUNT()?",opts:["ORDER BY","GROUP BY","GATHER BY","MATCH BY"],ans:1,exp:"The 'GROUP BY' clause is an analytical tool. It instructs the database engine to group identical data from designated columns into single summary rows. It is almost always paired with aggregate functions (like SUM or AVG) to calculate mathematical metrics for each distinct group, rather than the entire table."},hi:{q:"पंक्तियों को समूहित करने के लिए किस SQL क्लॉज की आवश्यकता होती है, जो आमतौर पर SUM() या COUNT() जैसे समग्र कार्यों (aggregate functions) के साथ उपयोग की जाती है?",opts:["ORDER BY","GROUP BY","GATHER BY","MATCH BY"],ans:1,exp:"'GROUP BY' क्लॉज एक विश्लेषणात्मक उपकरण है। यह डेटाबेस इंजन को निर्दिष्ट कॉलम से समान डेटा को एकल सारांश पंक्तियों में समूहित करने का निर्देश देता है। इसे लगभग हमेशा संपूर्ण तालिका के बजाय प्रत्येक विशिष्ट समूह के लिए गणितीय मीट्रिक की गणना करने के लिए (SUM या AVG जैसे) के साथ जोड़ा जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which aggregate function calculates the total sum of a numeric column in SQL?",opts:["TOTAL()","ADD()","SUM()","COUNT()"],ans:2,exp:"The 'SUM()' function is an aggregate mathematical function built into SQL. When applied to a specific column holding numeric values (e.g., SELECT SUM(Salary) FROM Employees), the database engine calculates and returns the absolute total combined sum of all the values present in that targeted column."},hi:{q:"SQL में कौन सा एग्रीगेट फ़ंक्शन एक संख्यात्मक कॉलम के कुल योग (sum) की गणना करता है?",opts:["TOTAL()","ADD()","SUM()","COUNT()"],ans:2,exp:"'SUM()' फ़ंक्शन SQL में निर्मित एक समग्र गणितीय कार्य है। जब संख्यात्मक मान रखने वाले विशिष्ट कॉलम पर लागू किया जाता है, तो डेटाबेस इंजन उस लक्षित कॉलम में मौजूद सभी मानों की गणना करता है और पूर्ण कुल संयुक्त योग देता है।"}},
{type:"mcq",diff:"medium",en:{q:"If you want to count the total number of records (rows) in a table named 'Students', which SQL query is correct?",opts:["SELECT SUM(rows) FROM Students;","SELECT COUNT(*) FROM Students;","SELECT NUMBER() FROM Students;","SELECT TOTAL(*) FROM Students;"],ans:1,exp:"The 'COUNT(*)' function evaluates the entire table and returns the exact numerical tally of all rows present, regardless of whether some columns contain NULL values. It is the standard, most heavily optimized way to quickly determine the overall size or record count of a dataset."},hi:{q:"यदि आप 'Students' नामक तालिका में रिकॉर्ड (पंक्तियों) की कुल संख्या की गणना करना चाहते हैं, तो कौन सी SQL क्वेरी सही है?",opts:["SELECT SUM(rows) FROM Students;","SELECT COUNT(*) FROM Students;","SELECT NUMBER() FROM Students;","SELECT TOTAL(*) FROM Students;"],ans:1,exp:"'COUNT(*)' फ़ंक्शन पूरी तालिका का मूल्यांकन करता है और मौजूद सभी पंक्तियों की सटीक संख्यात्मक गणना देता है, भले ही कुछ कॉलम में NULL मान हों। यह डेटासेट के समग्र आकार या रिकॉर्ड संख्या को जल्दी से निर्धारित करने का मानक, सबसे भारी अनुकूलित तरीका है।"}},
{type:"mcq",diff:"medium",en:{q:"Which clause must be used to filter groups of data AFTER the GROUP BY clause has been applied?",opts:["WHERE","FILTER","HAVING","LIMIT"],ans:2,exp:"This is a crucial SQL rule: The standard WHERE clause absolutely cannot evaluate aggregate functions. To filter results based on the output of an aggregate function (e.g., finding departments where the SUM of salaries is greater than $100,000), the 'HAVING' clause must be used immediately following the GROUP BY clause."},hi:{q:"GROUP BY क्लॉज लागू होने के बाद डेटा के समूहों को फ़िल्टर करने के लिए किस क्लॉज का उपयोग किया जाना चाहिए?",opts:["WHERE","FILTER","HAVING","LIMIT"],ans:2,exp:"यह एक महत्वपूर्ण SQL नियम है: मानक WHERE क्लॉज समग्र कार्यों (aggregate functions) का मूल्यांकन बिल्कुल नहीं कर सकता है। एक एग्रीगेट फ़ंक्शन के आउटपुट के आधार पर परिणामों को फ़िल्टर करने के लिए, GROUP BY क्लॉज के तुरंत बाद 'HAVING' क्लॉज का उपयोग किया जाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"Which operator is utilized within a WHERE clause to search for a specified pattern in a column, usually paired with wildcards?",opts:["MATCH","LIKE","SAME","EQUALS"],ans:1,exp:"The 'LIKE' logical operator is the backbone of SQL pattern matching. Instead of searching for an exact match using the '=' operator, LIKE is used in conjunction with wildcards (such as '%' or '_') to find strings that share a specific partial sequence, such as finding all names starting with 'S' (LIKE 'S%')."},hi:{q:"एक कॉलम में एक निर्दिष्ट पैटर्न की खोज करने के लिए WHERE क्लॉज के भीतर किस ऑपरेटर का उपयोग किया जाता है, जिसे आमतौर पर वाइल्डकार्ड के साथ जोड़ा जाता है?",opts:["MATCH","LIKE","SAME","EQUALS"],ans:1,exp:"'LIKE' तार्किक ऑपरेटर SQL पैटर्न मिलान की रीढ़ है। '=' ऑपरेटर का उपयोग करके सटीक मिलान खोजने के बजाय, LIKE का उपयोग वाइल्डकार्ड (जैसे '%' या '_') के संयोजन में किया जाता है, ताकि उन स्ट्रिंग्स को खोजा जा सके जो एक विशिष्ट आंशिक अनुक्रम साझा करते हैं, जैसे 'S' (LIKE 'S%') से शुरू होने वाले सभी नाम खोजना।"}},
{type:"mcq",diff:"medium",en:{q:"In standard SQL, which wildcard character specifically represents one single, solitary unknown character in a LIKE query?",opts:["% (Percent)","* (Asterisk)","_ (Underscore)","# (Hash)"],ans:2,exp:"While the percent sign (%) represents zero, one, or multiple characters, the underscore (_) wildcard is strictly positional. It represents exactly one single character. For example, the query 'LIKE '_at'' would successfully match three-letter words like 'Cat' or 'Bat', but would deliberately fail to match 'Boat'."},hi:{q:"मानक SQL में, कौन सा वाइल्डकार्ड वर्ण विशेष रूप से LIKE क्वेरी में एक एकल, अज्ञात वर्ण (single character) का प्रतिनिधित्व करता है?",opts:["% (Percent)","* (Asterisk)","_ (Underscore)","# (Hash)"],ans:2,exp:"जबकि प्रतिशत चिह्न (%) शून्य, एक या एकाधिक वर्णों का प्रतिनिधित्व करता है, अंडरस्कोर (_) वाइल्डकार्ड सख्ती से स्थितीय है। यह बिल्कुल एक वर्ण का प्रतिनिधित्व करता है। उदाहरण के लिए, क्वेरी 'LIKE '_at'' सफलतापूर्वक 'Cat' या 'Bat' जैसे तीन-अक्षर वाले शब्दों से मेल खाएगी, लेकिन 'Boat' से मेल नहीं खाएगी।"}},
{type:"mcq",diff:"medium",en:{q:"What does DCL stand for in database terminology?",opts:["Data Central Logic","Data Control Language","Document Command Language","Database Control Logic"],ans:1,exp:"DCL stands for Data Control Language. It represents the subset of SQL commands dedicated to enforcing database security. DCL commands control the granular access permissions, dictating exactly which users possess the authorization to view, alter, or drop specific data objects. The primary commands are GRANT and REVOKE."},hi:{q:"डेटाबेस शब्दावली में DCL का पूर्ण रूप क्या है?",opts:["डेटा सेंट्रल लॉजिक","डेटा कंट्रोल लैंग्वेज","दस्तावेज़ कमांड लैंग्वेज","डेटाबेस कंट्रोल लॉजिक"],ans:1,exp:"DCL का अर्थ डेटा कंट्रोल लैंग्वेज है। यह डेटाबेस सुरक्षा लागू करने के लिए समर्पित SQL कमांड के उपसमूह का प्रतिनिधित्व करता है। DCL कमांड पहुंच अनुमतियों को नियंत्रित करते हैं, यह तय करते हैं कि किन उपयोगकर्ताओं के पास विशिष्ट डेटा ऑब्जेक्ट देखने या बदलने का प्राधिकरण है। प्राथमिक आदेश GRANT और REVOKE हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which DDL command is used to permanently destroy an entire table along with all its structural definitions and contained data?",opts:["DELETE TABLE","REMOVE TABLE","DROP TABLE","TRUNCATE TABLE"],ans:2,exp:"The 'DROP TABLE' command is a highly destructive DDL operation. Executing it completely obliterates the table's structural schema from the database, instantly erasing all the data rows stored within it and severing any associated indexes or constraints. It cannot easily be undone."},hi:{q:"संपूर्ण तालिका को उसकी सभी संरचनात्मक परिभाषाओं और निहित डेटा के साथ स्थायी रूप से नष्ट करने के लिए किस DDL कमांड का उपयोग किया जाता है?",opts:["DELETE TABLE","REMOVE TABLE","DROP TABLE","TRUNCATE TABLE"],ans:2,exp:"'DROP TABLE' कमांड एक अत्यधिक विनाशकारी DDL ऑपरेशन है। इसे निष्पादित करने से डेटाबेस से तालिका का संरचनात्मक स्कीमा पूरी तरह से मिट जाता है, इसके भीतर संग्रहीत सभी डेटा पंक्तियों को तुरंत मिटा दिया जाता है और किसी भी संबंधित इंडेक्स को काट दिया जाता है। इसे आसानी से पूर्ववत नहीं किया जा सकता।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary difference between the TRUNCATE and DELETE commands in SQL?",opts:["TRUNCATE deletes the table structure; DELETE deletes rows","DELETE removes all rows extremely fast without logging; TRUNCATE deletes specific rows","TRUNCATE rapidly removes all rows without logging individual deletions; DELETE removes rows line-by-line and logs each action","There is no operational difference"],ans:2,exp:"DELETE is a DML command that scans and removes rows individually, logging each deletion in the transaction log, allowing for rollback. TRUNCATE is a much faster DDL command that instantly deallocates all data pages containing the table's records, effectively emptying the table without logging individual row deletions."},hi:{q:"SQL में TRUNCATE और DELETE कमांड के बीच प्राथमिक अंतर क्या है?",opts:["TRUNCATE टेबल संरचना को हटा देता है; DELETE पंक्तियों को हटा देता है","DELETE बिना लॉगिंग के बहुत तेजी से सभी पंक्तियों को हटा देता है; TRUNCATE विशिष्ट पंक्तियों को हटा देता है","TRUNCATE अलग-अलग विलोपन लॉग किए बिना सभी पंक्तियों को तेजी से हटा देता है; DELETE पंक्ति-दर-पंक्ति हटाता है और प्रत्येक क्रिया को लॉग करता है","कोई परिचालन अंतर नहीं है"],ans:2,exp:"DELETE एक DML कमांड है जो पंक्तियों को अलग-अलग स्कैन करता है और हटाता है, लेन-देन लॉग में प्रत्येक विलोपन को लॉग करता है, जिससे रोलबैक की अनुमति मिलती है। TRUNCATE एक बहुत तेज़ DDL कमांड है जो तालिका के रिकॉर्ड वाले सभी डेटा पृष्ठों को तुरंत खाली कर देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which SQL command is utilized to add a new column to an already existing table schema?",opts:["ADD COLUMN","UPDATE TABLE","ALTER TABLE","MODIFY SCHEMA"],ans:2,exp:"To implement structural changes to an existing table without destroying it, the 'ALTER TABLE' DDL command is used. By using the syntax 'ALTER TABLE table_name ADD column_name datatype', a database administrator can dynamically inject new columns, modify existing data types, or drop columns."},hi:{q:"पहले से मौजूद टेबल स्कीमा में नया कॉलम जोड़ने के लिए किस SQL कमांड का उपयोग किया जाता है?",opts:["ADD COLUMN","UPDATE TABLE","ALTER TABLE","MODIFY SCHEMA"],ans:2,exp:"किसी मौजूदा तालिका को नष्ट किए बिना उसमें संरचनात्मक परिवर्तनों को लागू करने के लिए, 'ALTER TABLE' DDL कमांड का उपयोग किया जाता है। 'ALTER TABLE table_name ADD column_name datatype' सिंटैक्स का उपयोग करके, एक डेटाबेस व्यवस्थापक गतिशील रूप से नए कॉलम इंजेक्ट कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"In MS Access, what field property is used to enforce conditions on data entry, restricting what values users can type into a field?",opts:["Input Mask","Default Value","Validation Rule","Format"],ans:2,exp:"The 'Validation Rule' property acts as a strict gatekeeper at the field level. An administrator can write a logical expression (e.g., >0 AND <100). If a user attempts to input data that violates this specific mathematical or logical rule, Access physically blocks the entry and throws an error message."},hi:{q:"MS Access में, डेटा प्रविष्टि (data entry) पर शर्तों को लागू करने के लिए किस फ़ील्ड प्रॉपर्टी का उपयोग किया जाता है, जो उपयोगकर्ताओं को फ़ील्ड में क्या मान टाइप कर सकते हैं, इसे प्रतिबंधित करता है?",opts:["Input Mask","Default Value","Validation Rule","Format"],ans:2,exp:"'वैलिडेशन रूल' (Validation Rule) प्रॉपर्टी फ़ील्ड स्तर पर एक सख्त द्वारपाल के रूप में कार्य करती है। एक व्यवस्थापक एक तार्किक अभिव्यक्ति लिख सकता है (उदा., >0 और <100)। यदि कोई उपयोगकर्ता ऐसे डेटा को इनपुट करने का प्रयास करता है जो इस नियम का उल्लंघन करता है, तो एक्सेस प्रविष्टि को अवरुद्ध करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which MS Access property provides a visual template (like dashes or parentheses) to guide a user formatting data entry, such as a phone number?",opts:["Validation Rule","Input Mask","Caption","Required"],ans:1,exp:"An 'Input Mask' is a structural formatting tool designed to facilitate standardized data entry and prevent typos. By defining a mask like '(000) 000-0000', Access physically renders those parentheses and dashes in the blank field, forcing the user to type exactly 10 digits into the appropriate slots."},hi:{q:"कौन सी MS Access प्रॉपर्टी फ़ोन नंबर जैसे डेटा प्रविष्टि को स्वरूपित करने वाले उपयोगकर्ता का मार्गदर्शन करने के लिए एक विज़ुअल टेम्प्लेट (जैसे डैश या कोष्ठक) प्रदान करती है?",opts:["Validation Rule","Input Mask","Caption","Required"],ans:1,exp:"'इनपुट मास्क' (Input Mask) एक संरचनात्मक स्वरूपण उपकरण है जिसे मानकीकृत डेटा प्रविष्टि की सुविधा और टाइपो को रोकने के लिए डिज़ाइन किया गया है। '(000) 000-0000' जैसे मास्क को परिभाषित करके, एक्सेस शारीरिक रूप से खाली क्षेत्र में उन कोष्ठकों और डैश को प्रस्तुत करता है, जिससे उपयोगकर्ता को टाइप करने के लिए मजबूर होना पड़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"If you want a specific value (like 'Active') to automatically populate in a field when creating a new record, which MS Access property should be set?",opts:["Validation Rule","Caption","Default Value","Input Mask"],ans:2,exp:"The 'Default Value' property drastically speeds up data entry for repetitive fields. When a new row is initialized, Access automatically injects the designated Default Value into that specific field. The user can either accept this automated value by tabbing past it, or manually type over it if necessary."},hi:{q:"यदि आप एक नया रिकॉर्ड बनाते समय किसी फ़ील्ड में एक विशिष्ट मान (जैसे 'सक्रिय' - 'Active') स्वचालित रूप से आबाद (populate) करना चाहते हैं, तो कौन सी MS Access प्रॉपर्टी सेट की जानी चाहिए?",opts:["Validation Rule","Caption","Default Value","Input Mask"],ans:2,exp:"'डिफ़ॉल्ट वैल्यू' प्रॉपर्टी दोहराव वाले क्षेत्रों के लिए डेटा प्रविष्टि को काफी तेज करती है। जब एक नई पंक्ति शुरू की जाती है, तो एक्सेस स्वचालित रूप से उस विशिष्ट क्षेत्र में नामित डिफ़ॉल्ट मान को इंजेक्ट करता है। उपयोगकर्ता या तो इसे स्वीकार कर सकता है, या यदि आवश्यक हो तो इसे मैन्युअल रूप से बदल सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Setting the 'Required' property of a field to 'Yes' in MS Access accomplishes what SQL equivalent constraint?",opts:["UNIQUE constraint","PRIMARY KEY constraint","NOT NULL constraint","FOREIGN KEY constraint"],ans:2,exp:"Changing the 'Required' property to 'Yes' in the Access Design View strictly forces the user to enter data into that specific field before saving the record. In standard SQL architecture, this mirrors the 'NOT NULL' constraint, physically preventing the field from ever being left empty or undefined."},hi:{q:"MS Access में किसी फ़ील्ड की 'Required' (आवश्यक) प्रॉपर्टी को 'Yes' पर सेट करने से कौन सा SQL समतुल्य बाधा (constraint) पूरा होता है?",opts:["UNIQUE constraint","PRIMARY KEY constraint","NOT NULL constraint","FOREIGN KEY constraint"],ans:2,exp:"एक्सेस डिज़ाइन व्यू में 'Required' प्रॉपर्टी को 'Yes' में बदलने से उपयोगकर्ता को रिकॉर्ड को सहेजने से पहले उस विशिष्ट फ़ील्ड में डेटा दर्ज करने के लिए सख्ती से मजबूर किया जाता है। मानक SQL वास्तुकला में, यह 'NOT NULL' बाधा को दर्शाता है, जो भौतिक रूप से फ़ील्ड को कभी भी खाली छोड़ने से रोकता है।"}},
{type:"mcq",diff:"medium",en:{q:"In MS Access, what does checking the 'Cascade Delete Related Records' box do?",opts:["It deletes the entire database if a virus is found","It prevents users from deleting any records","If a parent record is deleted, all dependent child records in linked tables are automatically deleted to prevent orphaned data","It deletes all tables immediately"],ans:2,exp:"Cascading Deletes are a powerful automated cleanup mechanism enforcing referential integrity. If a parent record (e.g., Customer #12) is permanently deleted, the database engine automatically hunts down and destroys all associated child records (e.g., all Orders placed by Customer #12) to ensure no orphaned data remains."},hi:{q:"MS Access में, 'कैस्केड डिलीट रिलेटेड रिकॉर्ड्स' (Cascade Delete Related Records) बॉक्स को चेक करने से क्या होता है?",opts:["यदि वायरस पाया जाता है तो यह संपूर्ण डेटाबेस को हटा देता है","यह उपयोगकर्ताओं को किसी भी रिकॉर्ड को हटाने से रोकता है","यदि कोई पैरेंट (parent) रिकॉर्ड हटा दिया जाता है, तो लिंक की गई तालिकाओं में सभी आश्रित बाल (child) रिकॉर्ड स्वचालित रूप से हटा दिए जाते हैं ताकि अनाथ डेटा को रोका जा सके","यह सभी तालिकाओं को तुरंत हटा देता है"],ans:2,exp:"कैस्केडिंग डिलीट (Cascading Deletes) एक शक्तिशाली स्वचालित सफाई तंत्र है जो संदर्भ अखंडता को लागू करता है। यदि कोई पैरेंट रिकॉर्ड (उदा., ग्राहक #12) स्थायी रूप से हटा दिया जाता है, तो डेटाबेस इंजन स्वचालित रूप से सभी संबंधित बाल रिकॉर्ड (उदा., ग्राहक #12 द्वारा दिए गए सभी आदेश) को हटा देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which specialized type of Access query displays a dialog box asking the user to input dynamic criteria (like a date range) right before it runs?",opts:["Select Query","Crosstab Query","Parameter Query","Append Query"],ans:2,exp:"A 'Parameter Query' is highly interactive. Instead of hardcoding a specific search term inside the query builder (like 'London'), the designer inserts a bracketed prompt like [Enter City Name]. Every time the query is executed, it pauses, popping up a dialog box requiring the user to type the criteria live."},hi:{q:"किस विशेष प्रकार की एक्सेस क्वेरी एक डायलॉग बॉक्स प्रदर्शित करती है जिसमें उपयोगकर्ता से इसे चलाने से ठीक पहले गतिशील मानदंड (dynamic criteria) (जैसे दिनांक सीमा) इनपुट करने के लिए कहा जाता है?",opts:["सिलेक्ट क्वेरी (Select Query)","क्रॉसटैब क्वेरी (Crosstab Query)","पैरामीटर क्वेरी (Parameter Query)","एपेंड क्वेरी (Append Query)"],ans:2,exp:"'पैरामीटर क्वेरी' अत्यधिक इंटरैक्टिव है। क्वेरी बिल्डर (जैसे 'लंदन') के अंदर एक विशिष्ट खोज शब्द को हार्डकोडिंग करने के बजाय, डिजाइनर [Enter City Name] जैसा एक ब्रैकेट वाला संकेत सम्मिलित करता है। हर बार क्वेरी निष्पादित होने पर, यह रुक जाता है, एक संवाद बॉक्स पॉप अप करता है जिसमें उपयोगकर्ता को मानदंड टाइप करने की आवश्यकता होती है।"}},
{type:"mcq",diff:"medium",en:{q:"Which MS Access query fundamentally summarizes numeric data into a spreadsheet-like grid, grouping one set of values on the left (Row Headings) and another set across the top (Column Headings)?",opts:["Make Table Query","Update Query","Crosstab Query","Delete Query"],ans:2,exp:"The 'Crosstab Query' is an advanced analytical tool analogous to an Excel PivotTable. It aggregates data (calculating sums, averages, or counts) and structures the output in a compact, two-dimensional matrix grid, defining data both vertically by row headers and horizontally by column headers for easy comparison."},hi:{q:"कौन सी MS Access क्वेरी मूल रूप से सांख्यिक डेटा को स्प्रेडशीट जैसे ग्रिड में सारांशित करती है, बायीं ओर (Row Headings) मानों के एक सेट को समूहीकृत करती है और दूसरे सेट को शीर्ष (Column Headings) पर रखती है?",opts:["मेक टेबल क्वेरी","अपडेट क्वेरी","क्रॉसटैब क्वेरी (Crosstab Query)","डिलीट क्वेरी"],ans:2,exp:"'क्रॉसटैब क्वेरी' एक्सेल पिवटटेबल के समान एक उन्नत विश्लेषणात्मक उपकरण है। यह डेटा एकत्र करता है (रकम, औसत, या गणना की गणना करता है) और आउटपुट को एक कॉम्पैक्ट, दो-आयामी मैट्रिक्स ग्रिड में संरचना करता है, आसान तुलना के लिए डेटा को लंबवत और क्षैतिज रूप से परिभाषित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"In MS Access, 'Append', 'Update', 'Make Table', and 'Delete' queries are collectively categorized as what type of queries?",opts:["Select Queries","Passive Queries","Action Queries","Static Queries"],ans:2,exp:"Unlike a standard Select query that simply retrieves and displays data, an 'Action Query' makes massive, physical structural or data changes to the database in a single operation. Because they actively modify or destroy bulk data, Access flags Action Queries with distinct exclamation point (!) icons as a warning."},hi:{q:"MS Access में, 'Append', 'Update', 'Make Table' और 'Delete' प्रश्नों को सामूहिक रूप से किस प्रकार के प्रश्नों के रूप में वर्गीकृत किया गया है?",opts:["सिलेक्ट क्वेरीज़","पैसिव क्वेरीज़","एक्शन क्वेरीज़ (Action Queries)","स्टैटिक क्वेरीज़"],ans:2,exp:"एक मानक सिलेक्ट क्वेरी के विपरीत जो डेटा को पुनः प्राप्त और प्रदर्शित करती है, 'एक्शन क्वेरी' एक ही ऑपरेशन में डेटाबेस में बड़े पैमाने पर, भौतिक संरचनात्मक या डेटा परिवर्तन करती है। क्योंकि वे सक्रिय रूप से थोक डेटा को संशोधित या नष्ट करते हैं, एक्सेस एक चेतावनी के रूप में विशिष्ट विस्मयादिबोधक बिंदु (!) आइकन के साथ एक्शन क्वेरीज़ को फ़्लैग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"In the context of the SQL INSERT statement, if you do not specify the column names, what critical rule must be followed?",opts:["You must only insert text data","The values must be provided in the exact same order as the columns are defined in the table schema","You must use the UPDATE command instead","You cannot omit column names without getting an error"],ans:1,exp:"While specifying column names in an INSERT INTO statement is best practice, omitting them is allowed. However, doing so strictly mandates that the VALUES() array must contain data mapping to every single column in the table, and the data must perfectly match the exact sequential order of the table's schema."},hi:{q:"SQL INSERT कथन के संदर्भ में, यदि आप कॉलम नाम निर्दिष्ट नहीं करते हैं, तो किस महत्वपूर्ण नियम का पालन किया जाना चाहिए?",opts:["आपको केवल टेक्स्ट डेटा डालना होगा","मान उसी क्रम में प्रदान किए जाने चाहिए जैसे कॉलम टेबल स्कीमा में परिभाषित किए गए हैं","आपको इसके बजाय UPDATE कमांड का उपयोग करना चाहिए","आप त्रुटि प्राप्त किए बिना कॉलम नाम नहीं छोड़ सकते"],ans:1,exp:"यद्यपि INSERT INTO स्टेटमेंट में कॉलम नाम निर्दिष्ट करना सर्वोत्तम अभ्यास है, लेकिन उन्हें छोड़ना अनुमत है। हालाँकि, ऐसा करने से कड़ाई से यह अनिवार्य हो जाता है कि VALUES() सरणी में तालिका के हर एक कॉलम में डेटा मैपिंग होनी चाहिए, और डेटा तालिका के स्कीमा के सटीक अनुक्रमिक क्रम से पूरी तरह मेल खाना चाहिए।"}},
{type:"mcq",diff:"medium",en:{q:"What does the SQL command 'DESCRIBE table_name;' or 'DESC table_name;' do?",opts:["It provides a textual summary of the data inside the table","It outputs the structural architecture of the table, listing columns, data types, and key constraints","It drops the table","It sorts the table in descending order"],ans:1,exp:"The 'DESCRIBE' (or DESC) command is a utility command used to investigate database architecture. Executing it returns the table's structural schema, providing a concise list of all column names, their assigned data types, whether they accept NULL values, and which columns act as Primary or Foreign keys."},hi:{q:"SQL कमांड 'DESCRIBE table_name;' या 'DESC table_name;' क्या करता है?",opts:["यह तालिका के अंदर डेटा का पाठ्य सारांश प्रदान करता है","यह कॉलम, डेटा प्रकार और प्रमुख बाधाओं को सूचीबद्ध करते हुए तालिका के संरचनात्मक वास्तुकला को आउटपुट करता है","यह टेबल को हटा देता है (drop)","यह तालिका को अवरोही क्रम (descending) में सॉर्ट करता है"],ans:1,exp:"'DESCRIBE' (या DESC) कमांड डेटाबेस आर्किटेक्चर की जांच करने के लिए उपयोग की जाने वाली एक उपयोगिता कमांड है। इसे निष्पादित करने से तालिका का संरचनात्मक स्कीमा वापस आ जाता है, सभी कॉलम नामों की एक संक्षिप्त सूची, उनके निर्दिष्ट डेटा प्रकार, क्या वे शून्य मान स्वीकार करते हैं, और कुंजी आदि के बारे में जानकारी मिलती है।"}},
// MEDIUM - TRUE/FALSE (2 Questions)
{type:"tf",diff:"medium",en:{q:"The SQL WHERE clause can evaluate aggregate functions directly, such as WHERE SUM(Salary) > 50000.",opts:["True","False"],ans:1,exp:"False. By SQL architectural design, the WHERE clause evaluates individual row constraints before grouping occurs. It is strictly incapable of evaluating aggregate functions. To filter mathematical aggregations (like SUM or COUNT), the query must use the HAVING clause located after the GROUP BY statement."},hi:{q:"SQL WHERE क्लॉज सीधे समग्र कार्यों (aggregate functions) का मूल्यांकन कर सकता है, जैसे कि WHERE SUM(Salary) > 50000।",opts:["सही","गलत"],ans:1,exp:"गलत। SQL आर्किटेक्चरल डिज़ाइन द्वारा, WHERE क्लॉज समूहीकरण (grouping) होने से पहले अलग-अलग पंक्ति बाधाओं का मूल्यांकन करता है। यह समग्र कार्यों का मूल्यांकन करने में कड़ाई से असमर्थ है। गणितीय एकत्रीकरण (जैसे SUM या COUNT) को फ़िल्टर करने के लिए, क्वेरी को GROUP BY कथन के बाद स्थित HAVING क्लॉज का उपयोग करना चाहिए।"}},
{type:"tf",diff:"medium",en:{q:"When executing an INNER JOIN between two tables, the result-set will only contain rows where there is a direct match in both tables based on the linked key.",opts:["True","False"],ans:0,exp:"True. An INNER JOIN acts as a strict intersection mechanism. It logically evaluates both tables and outputs a row exclusively if the defined linking condition (e.g., TableA.ID = TableB.ID) evaluates to exactly true in both tables. Any unmatched rows from either side are completely discarded from the result."},hi:{q:"दो तालिकाओं के बीच 'INNER JOIN' निष्पादित करते समय, परिणाम-सेट में केवल वे पंक्तियां होंगी जहां लिंक की गई कुंजी के आधार पर दोनों तालिकाओं में सीधा मिलान (direct match) होगा।",opts:["सही","गलत"],ans:0,exp:"सही। एक इनर जॉइन (INNER JOIN) एक सख्त चौराहे (intersection) तंत्र के रूप में कार्य करता है। यह तार्किक रूप से दोनों तालिकाओं का मूल्यांकन करता है और एक पंक्ति को विशेष रूप से आउटपुट करता है यदि परिभाषित लिंकिंग स्थिति (उदा., TableA.ID = TableB.ID) दोनों तालिकाओं में ठीक सत्य का मूल्यांकन करती है। कोई भी बेजोड़ पंक्तियाँ परिणाम से पूरी तरह से हटा दी जाती हैं।"}},

// HARD - MCQ (28 Questions)
{type:"mcq",diff:"hard",en:{q:"In Database Normalization, what is the defining requirement to achieve First Normal Form (1NF)?",opts:["Removing all foreign keys","Ensuring every column contains atomic (indivisible) values and eliminating repeating groups","Removing all transitive dependencies","Splitting the table into three separate views"],ans:1,exp:"First Normal Form (1NF) establishes the baseline for relational databases. It strictly prohibits arrays, lists, or multiple values inside a single database cell. To comply with 1NF, every attribute must hold an atomic, indivisible value, and repeating groups of data must be moved into separate records or tables."},hi:{q:"डेटाबेस नॉर्मलाइज़ेशन (Database Normalization) में, फर्स्ट नॉर्मल फॉर्म (1NF) प्राप्त करने के लिए परिभाषित आवश्यकता क्या है?",opts:["सभी विदेशी कुंजियों (foreign keys) को हटाना","यह सुनिश्चित करना कि प्रत्येक कॉलम में परमाणु (अविभाज्य / atomic) मान हों और दोहराए जाने वाले समूहों को समाप्त करना","सभी सकर्मक निर्भरता (transitive dependencies) को हटाना","तालिका को तीन अलग-अलग दृश्यों में विभाजित करना"],ans:1,exp:"फर्स्ट नॉर्मल फॉर्म (1NF) रिलेशनल डेटाबेस के लिए आधार रेखा स्थापित करता है। यह एक डेटाबेस सेल के अंदर एरे, सूचियों या कई मानों को सख्ती से प्रतिबंधित करता है। 1NF का अनुपालन करने के लिए, प्रत्येक विशेषता में एक परमाणु, अविभाज्य मूल्य होना चाहिए, और डेटा के दोहराए जाने वाले समूहों को अलग-अलग रिकॉर्ड या तालिकाओं में ले जाया जाना चाहिए।"}},
{type:"mcq",diff:"hard",en:{q:"Second Normal Form (2NF) builds upon 1NF. What specific flaw does 2NF seek to eliminate?",opts:["Transitive Dependencies","Multi-valued attributes","Partial Dependencies on a composite primary key","Data encryption errors"],ans:2,exp:"Second Normal Form (2NF) is relevant primarily for tables utilizing composite primary keys (keys made of multiple columns). 2NF dictates that every non-key attribute must be fully functionally dependent on the ENTIRE composite primary key, thereby eliminating 'partial dependencies' to drastically reduce data redundancy."},hi:{q:"सेकंड नॉर्मल फॉर्म (2NF) 1NF पर आधारित है। 2NF किस विशिष्ट दोष को दूर करना चाहता है?",opts:["सकर्मक निर्भरता (Transitive Dependencies)","बहु-मूल्यवान विशेषताएँ (Multi-valued attributes)","समग्र प्राथमिक कुंजी (composite primary key) पर आंशिक निर्भरता (Partial Dependencies)","डेटा एन्क्रिप्शन त्रुटियां"],ans:2,exp:"सेकंड नॉर्मल फॉर्म (2NF) मुख्य रूप से समग्र प्राथमिक कुंजी (एकाधिक कॉलम से बनी चाबियां) का उपयोग करने वाली तालिकाओं के लिए प्रासंगिक है। 2NF यह तय करता है कि प्रत्येक गैर-कुंजी विशेषता को संपूर्ण समग्र प्राथमिक कुंजी पर पूरी तरह कार्यात्मक रूप से निर्भर होना चाहिए, जिससे डेटा अतिरेक को कम करने के लिए 'आंशिक निर्भरता' को समाप्त किया जा सके।"}},
{type:"mcq",diff:"hard",en:{q:"To reach Third Normal Form (3NF), a database must be in 2NF and must completely eliminate which of the following?",opts:["Primary keys","Transitive Dependencies (non-key fields depending on other non-key fields)","Numeric data types","Indexes"],ans:1,exp:"Third Normal Form (3NF) focuses on the relationship between non-key data. It strictly forbids Transitive Dependencies, meaning a non-key column cannot depend on another non-key column. Every non-key field must depend on 'the key, the whole key, and nothing but the key.' If transitive logic exists, it belongs in a new table."},hi:{q:"थर्ड नॉर्मल फॉर्म (3NF) तक पहुंचने के लिए, डेटाबेस 2NF में होना चाहिए और निम्नलिखित में से किसे पूरी तरह से खत्म करना चाहिए?",opts:["प्राइमरी की","सकर्मक निर्भरता (Transitive Dependencies - अन्य गैर-कुंजी फ़ील्ड पर निर्भर गैर-कुंजी फ़ील्ड)","संख्यात्मक डेटा प्रकार","इंडेक्स"],ans:1,exp:"थर्ड नॉर्मल फॉर्म (3NF) गैर-कुंजी डेटा के बीच संबंध पर केंद्रित है। यह सकर्मक निर्भरता को सख्ती से रोकता है, जिसका अर्थ है कि एक गैर-कुंजी कॉलम दूसरे गैर-कुंजी कॉलम पर निर्भर नहीं हो सकता है। यदि सकर्मक तर्क मौजूद है, तो यह एक नई तालिका से संबंधित है।"}},
{type:"mcq",diff:"hard",en:{q:"In modern DBMS theory, transactions must maintain the 'ACID' properties to ensure absolute reliability. What does ACID stand for?",opts:["Automated, Connected, Independent, Durable","Atomicity, Consistency, Isolation, Durability","Asynchronous, Concurrent, Isolated, Dynamic","All Columns In Database"],ans:1,exp:"The ACID properties are fundamental theoretical guarantees provided by a robust RDBMS transaction engine. Atomicity ensures all parts of a transaction succeed or fail together. Consistency ensures valid data states. Isolation prevents concurrent transactions from interfering. Durability guarantees committed data survives catastrophic power failures."},hi:{q:"आधुनिक DBMS सिद्धांत में, पूर्ण विश्वसनीयता सुनिश्चित करने के लिए लेनदेन (transactions) को 'ACID' गुणों को बनाए रखना चाहिए। ACID का पूर्ण रूप क्या है?",opts:["Automated, Connected, Independent, Durable","Atomicity, Consistency, Isolation, Durability","Asynchronous, Concurrent, Isolated, Dynamic","All Columns In Database"],ans:1,exp:"ACID गुण एक मजबूत RDBMS लेनदेन इंजन द्वारा प्रदान की गई मौलिक सैद्धांतिक गारंटी हैं। परमाणुता (Atomicity) यह सुनिश्चित करती है कि लेन-देन के सभी भाग एक साथ सफल या विफल हों। संगति (Consistency) वैध डेटा स्थिति सुनिश्चित करती है। अलगाव (Isolation) समवर्ती लेनदेन को हस्तक्षेप करने से रोकता है। स्थायित्व (Durability) प्रतिबद्ध डेटा विनाशकारी बिजली विफलताओं से बचने की गारंटी देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Focusing on the 'A' in ACID properties, what does 'Atomicity' specifically guarantee in a database transaction?",opts:["It shrinks the database size to a microscopic level","It guarantees the transaction completes at high speed","It operates on the 'All or Nothing' rule—either the entire complex transaction completes successfully, or it completely fails and rolls back, leaving no partial data","It encrypts data into atoms"],ans:2,exp:"Atomicity dictates the 'All or Nothing' proposition of a transaction. If transferring money involves withdrawing from Account A and depositing to Account B, Atomicity guarantees both operations occur perfectly. If the deposit step fails, the withdrawal is instantly rolled back, physically preventing the database from saving a corrupt, halfway state."},hi:{q:"ACID गुणों में 'A' पर ध्यान केंद्रित करते हुए, डेटाबेस लेनदेन में 'Atomicity' विशेष रूप से क्या गारंटी देता है?",opts:["यह डेटाबेस के आकार को सूक्ष्म स्तर तक सिकोड़ देता है","यह गारंटी देता है कि लेनदेन उच्च गति से पूरा होता है","यह 'सब कुछ या कुछ नहीं' (All or Nothing) नियम पर काम करता है-या तो संपूर्ण जटिल लेनदेन सफलतापूर्वक पूरा हो जाता है, या यह पूरी तरह से विफल हो जाता है और वापस आ जाता है, कोई आंशिक डेटा नहीं छोड़ता है","यह डेटा को परमाणुओं में एन्क्रिप्ट करता है"],ans:2,exp:"परमाणुता (Atomicity) लेन-देन के 'ऑल या नथिंग' प्रस्ताव को निर्देशित करती है। यदि धन हस्तांतरित करने में खाता A से निकालना और खाता B में जमा करना शामिल है, तो परमाणुता दोनों कार्यों की गारंटी देती है। यदि जमा चरण विफल हो जाता है, तो वापसी तुरंत वापस आ जाती है (rolled back), भौतिक रूप से डेटाबेस को भ्रष्ट, आधे-अधूरे राज्य को सहेजने से रोकती है।"}},
{type:"mcq",diff:"hard",en:{q:"In SQL Join operations, what is the distinguishing behavior of a 'LEFT JOIN' (or Left Outer Join)?",opts:["It only returns rows with exact matches in both tables","It throws an error if tables are not identical","It unconditionally returns EVERY row from the primary (Left) table, and only the matching rows from the secondary (Right) table, padding with NULLs where no match exists","It deletes the left table"],ans:2,exp:"Unlike an Inner Join, a LEFT JOIN preserves data. It guarantees that absolutely every record residing in the 'Left' table (the one specified first in the SQL syntax) is included in the output. If the database engine finds no logically corresponding matching record in the 'Right' table, it fills those column fields with NULL values."},hi:{q:"SQL जॉइन ऑपरेशंस में, 'LEFT JOIN' (या लेफ्ट आउटर जॉइन) का विशिष्ट व्यवहार क्या है?",opts:["यह केवल दोनों तालिकाओं में सटीक मिलान वाली पंक्तियाँ देता है","यदि तालिकाएँ समान नहीं हैं तो यह एक त्रुटि देता है","यह बिना शर्त प्राथमिक (बाएं) तालिका से हर पंक्ति को वापस करता है, और माध्यमिक (दाएं) तालिका से केवल मिलान करने वाली पंक्तियां, जहां कोई मिलान मौजूद नहीं है, NULLs के साथ पैडिंग करता है","यह बाईं तालिका को हटा देता है"],ans:2,exp:"इनर जॉइन के विपरीत, एक LEFT JOIN डेटा को संरक्षित करता है। यह गारंटी देता है कि 'लेफ्ट' टेबल (SQL सिंटैक्स में पहले निर्दिष्ट किया गया है) में रहने वाला बिल्कुल हर रिकॉर्ड आउटपुट में शामिल है। यदि डेटाबेस इंजन को 'राइट' टेबल में कोई तार्किक रूप से संबंधित मिलान रिकॉर्ड नहीं मिलता है, तो यह उन कॉलम फ़ील्ड को NULL मानों से भर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"What devastating mathematical consequence occurs if two tables are joined via a CROSS JOIN (Cartesian Product) without any WHERE filtering conditions? Table A has 10 rows, Table B has 20 rows.",opts:["The result is an error","The result is 30 rows (10+20)","The result is 200 rows (10 x 20), pairing every single row in Table A with every single row in Table B","The result is 10 rows"],ans:2,exp:"A CROSS JOIN inherently lacks a linking logical condition. Therefore, the database engine executes a full Cartesian Product. It systematically multiplies the data sets, forcefully combining every single row from Table A with every single row from Table B. 10 rows × 20 rows results in a massive 200-row output, which can crash servers on large datasets."},hi:{q:"यदि बिना किसी WHERE फ़िल्टरिंग शर्तों के CROSS JOIN (Cartesian Product) के माध्यम से दो तालिकाओं को जोड़ा जाता है, तो क्या विनाशकारी गणितीय परिणाम होता है? टेबल A में 10 पंक्तियाँ हैं, टेबल B में 20 पंक्तियाँ हैं।",opts:["परिणाम एक त्रुटि है","परिणाम 30 पंक्तियाँ (10+20) है","परिणाम 200 पंक्तियाँ (10 x 20) है, जो तालिका A की प्रत्येक पंक्ति को तालिका B की प्रत्येक पंक्ति के साथ जोड़ता है","परिणाम 10 पंक्तियाँ है"],ans:2,exp:"क्रॉस जॉइन (CROSS JOIN) में स्वाभाविक रूप से एक लिंकिंग तार्किक स्थिति का अभाव होता है। इसलिए, डेटाबेस इंजन पूर्ण कार्टेशियन उत्पाद निष्पादित करता है। यह व्यवस्थित रूप से डेटा सेट को गुणा करता है, तालिका ए से हर एक पंक्ति को तालिका बी से हर एक पंक्ति के साथ जोड़ता है। 10 पंक्तियाँ × 20 पंक्तियों के परिणामस्वरूप 200-पंक्ति आउटपुट होता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which specific SQL keyword is used immediately after SELECT to forcefully eliminate any duplicate records from the final retrieved result-set?",opts:["UNIQUE","DISTINCT","SINGLE","FILTER"],ans:1,exp:"The 'DISTINCT' keyword operates as a strict uniqueness filter. When writing 'SELECT DISTINCT City FROM Customers', the database engine pulls all city values, scans them, and deliberately drops all duplicate entries, outputting an absolutely clean list of unique city names, which is vital for precise statistical counting."},hi:{q:"अंतिम पुनर्प्राप्त परिणाम-सेट (result-set) से किसी भी डुप्लिकेट रिकॉर्ड को बलपूर्वक समाप्त करने के लिए SELECT के तुरंत बाद किस विशिष्ट SQL कीवर्ड का उपयोग किया जाता है?",opts:["UNIQUE","DISTINCT","SINGLE","FILTER"],ans:1,exp:"'DISTINCT' कीवर्ड सख्त विशिष्टता फ़िल्टर (uniqueness filter) के रूप में काम करता है। 'SELECT DISTINCT City FROM Customers' लिखते समय, डेटाबेस इंजन सभी शहर के मान खींचता है, उन्हें स्कैन करता है, और जानबूझकर सभी डुप्लिकेट प्रविष्टियों को छोड़ देता है, अद्वितीय शहर के नामों की एक बिल्कुल साफ सूची आउटपुट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which SQL operator serves as a highly efficient shorthand for chaining multiple 'OR' conditions against the exact same column?",opts:["BETWEEN","LIKE","IN","ALL"],ans:2,exp:"The 'IN' operator provides elegant, optimized syntax. Instead of writing cumbersome code like `WHERE ID=1 OR ID=5 OR ID=9`, a developer simply writes `WHERE ID IN (1, 5, 9)`. The database engine checks if the column value matches ANY of the discreet values provided within the enclosed array list."},hi:{q:"कौन सा SQL ऑपरेटर सटीक एक ही कॉलम के विरुद्ध कई 'OR' शर्तों को श्रृंखलाबद्ध करने के लिए अत्यधिक कुशल शॉर्टहैंड के रूप में कार्य करता है?",opts:["BETWEEN","LIKE","IN","ALL"],ans:2,exp:"'IN' ऑपरेटर सुरुचिपूर्ण, अनुकूलित सिंटैक्स प्रदान करता है। `WHERE ID=1 OR ID=5 OR ID=9` जैसे बोझिल कोड लिखने के बजाय, एक डेवलपर केवल `WHERE ID IN (1, 5, 9)` लिखता है। डेटाबेस इंजन यह जांचता है कि क्या कॉलम मान संलग्न सरणी (array list) सूची के भीतर प्रदान किए गए किसी भी विवेकशील मान से मेल खाता है।"}},
{type:"mcq",diff:"hard",en:{q:"The SQL 'BETWEEN' operator evaluates ranges. Which statement is mathematically true regarding how BETWEEN handles the boundary values?",opts:["It excludes both the start and end values","It is fully inclusive, meaning it encompasses both the exact starting value and the exact ending value","It includes the start value but excludes the end value","It behaves randomly depending on the database"],ans:1,exp:"By universal SQL standard definitions, the 'BETWEEN' logical operator is strictly inclusive. A clause written as `WHERE Price BETWEEN 10 AND 20` will successfully return records where the price is precisely 10, precisely 20, or any numerical fractional value falling seamlessly between them."},hi:{q:"SQL 'BETWEEN' ऑपरेटर श्रेणियों (ranges) का मूल्यांकन करता है। 'BETWEEN' सीमा मानों को कैसे संभालता है, इसके बारे में कौन सा कथन गणितीय रूप से सत्य है?",opts:["यह प्रारंभ और अंत दोनों मानों को छोड़ देता है","यह पूरी तरह से समावेशी है, जिसका अर्थ है कि यह सटीक प्रारंभिक मूल्य और सटीक अंतिम मूल्य दोनों को शामिल करता है","इसमें प्रारंभ मान शामिल है लेकिन अंतिम मान को छोड़ देता है","यह डेटाबेस के आधार पर बेतरतीब ढंग से व्यवहार करता है"],ans:1,exp:"सार्वभौमिक SQL मानक परिभाषाओं के अनुसार, 'BETWEEN' तार्किक ऑपरेटर कड़ाई से समावेशी (inclusive) है। `WHERE Price BETWEEN 10 AND 20` के रूप में लिखा गया एक क्लॉज सफलतापूर्वक उन रिकॉर्ड्स को वापस कर देगा जहां कीमत ठीक 10, ठीक 20 है, या कोई भी संख्यात्मक भिन्नात्मक मूल्य उनके बीच निर्बाध रूप से गिरता है।"}},
{type:"mcq",diff:"hard",en:{q:"What critical difference separates a 'Primary Key' from a 'Unique Key' constraint in modern databases?",opts:["A Unique Key allows numbers only, Primary Key allows text","A table can have multiple Unique Keys, and a Unique Key explicitly allows one NULL value, whereas a Primary Key allows absolutely zero NULLs and only one exists per table","There is zero difference","Primary Keys are used for sorting only"],ans:1,exp:"While both keys strictly enforce uniqueness to prevent duplicates, their architectural roles differ. A database table is limited to exactly one Primary Key, which absolutely forbids NULLs. Conversely, a table can be engineered with multiple Unique Keys (like email addresses or SSNs), and standard SQL allows a Unique column to store exactly one NULL value."},hi:{q:"आधुनिक डेटाबेस में 'प्राइमरी की' (Primary Key) को 'यूनीक की' (Unique Key) बाधा से क्या महत्वपूर्ण अंतर अलग करता है?",opts:["एक यूनीक की केवल संख्याओं की अनुमति देती है, प्राइमरी की पाठ की अनुमति देती है","एक तालिका में एकाधिक यूनीक कीज़ हो सकती हैं, और एक यूनीक की स्पष्ट रूप से एक शून्य (NULL) मान की अनुमति देती है, जबकि एक प्राइमरी की बिल्कुल शून्य (NULL) की अनुमति नहीं देती है और प्रति तालिका केवल एक मौजूद है","शून्य अंतर है","प्राइमरी कीज़ का उपयोग केवल छँटाई (sorting) के लिए किया जाता है"],ans:1,exp:"जबकि दोनों कुंजियाँ डुप्लिकेट को रोकने के लिए विशिष्टता को सख्ती से लागू करती हैं, उनकी वास्तुशिल्प भूमिकाएँ भिन्न होती हैं। एक डेटाबेस तालिका ठीक एक प्राइमरी की तक सीमित है, जो NULLs को बिल्कुल मना करती है। इसके विपरीत, एक तालिका को एकाधिक यूनीक कीज़ (जैसे ईमेल पते) के साथ इंजीनियर किया जा सकता है, और मानक SQL एक अद्वितीय कॉलम को ठीक एक NULL मान संग्रहीत करने की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In relational database design, what is a 'Composite Key'?",opts:["A key made of encryption algorithms","A physical hardware key used to lock servers","A sophisticated Primary Key specifically engineered by combining two or more separate columns together to guarantee absolute row uniqueness","A key that deletes data"],ans:2,exp:"A Composite Key is heavily utilized in junction tables or complex logical designs. When no single column contains sufficient entropy to guarantee uniqueness (like a list of generic first names), the architect combines two or more columns (e.g., RoomNumber AND TimeSlot). The combination of those specific columns forms one uncrackable Primary Key."},hi:{q:"रिलेशनल डेटाबेस डिज़ाइन में, 'कम्पोजिट की' (Composite Key) क्या है?",opts:["एन्क्रिप्शन एल्गोरिदम से बनी एक कुंजी","सर्वर को लॉक करने के लिए उपयोग की जाने वाली एक भौतिक हार्डवेयर कुंजी","पूर्ण पंक्ति विशिष्टता (row uniqueness) की गारंटी के लिए दो या दो से अधिक अलग-अलग कॉलम को एक साथ जोड़कर विशेष रूप से इंजीनियर की गई एक परिष्कृत प्राइमरी की","एक कुंजी जो डेटा को हटा देती है"],ans:2,exp:"जंक्शन तालिकाओं या जटिल तार्किक डिजाइनों में एक कम्पोजिट की (Composite Key) का भारी उपयोग किया जाता है। जब किसी एक कॉलम में विशिष्टता (जैसे सामान्य प्रथम नामों की सूची) की गारंटी देने के लिए पर्याप्त एन्ट्रापी नहीं होती है, तो वास्तुकार दो या दो से अधिक कॉलम (उदा., RoomNumber AND TimeSlot) को जोड़ता है। उन विशिष्ट स्तंभों का संयोजन एक अभेद्य प्राथमिक कुंजी बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In SQL terminology, what is a 'View'?",opts:["A graphical user interface software","A virtual table physically storing no data of its own, constructed dynamically by a saved SQL SELECT query running against actual base tables","A command to increase monitor resolution","A backup file of the database"],ans:1,exp:"A SQL 'View' is fundamentally a saved, named query that acts exactly like a virtual table. It physically stores zero data bytes on the hard drive. Whenever a user queries the View, the underlying complex SELECT statement actively fetches and synthesizes the fresh data live from the heavy base tables, masking their complexity."},hi:{q:"SQL शब्दावली में, 'व्यू' (View) क्या है?",opts:["एक ग्राफिकल यूजर इंटरफेस सॉफ्टवेयर","एक आभासी (virtual) तालिका जो भौतिक रूप से अपना कोई डेटा संग्रहीत नहीं करती है, जिसे वास्तविक आधार तालिकाओं के विरुद्ध चलने वाले सहेजे गए SQL SELECT क्वेरी द्वारा गतिशील रूप से बनाया गया है","मॉनिटर रिज़ॉल्यूशन बढ़ाने के लिए एक कमांड","डेटाबेस की एक बैकअप फ़ाइल"],ans:1,exp:"एक SQL 'व्यू' मौलिक रूप से एक सहेजी गई, नामित क्वेरी है जो बिल्कुल एक आभासी (virtual) तालिका की तरह काम करती है। यह भौतिक रूप से हार्ड ड्राइव पर शून्य डेटा बाइट्स संग्रहीत करता है। जब भी कोई उपयोगकर्ता दृश्य को क्वेरी करता है, तो अंतर्निहित जटिल SELECT स्टेटमेंट सक्रिय रूप से भारी आधार तालिकाओं से ताजा डेटा लाइव प्राप्त करता है और संश्लेषित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is a 'Stored Procedure' in an RDBMS?",opts:["A manual detailing how to install the software","A pre-compiled collection of complex SQL statements and logical programming code physically stored and executed directly inside the database server engine","A routine that restarts the computer","A cloud storage protocol"],ans:1,exp:"A 'Stored Procedure' is incredibly powerful. It allows developers to write extensive chunks of SQL logic, including IF/THEN statements and loops, and save it directly onto the database server itself. Applications simply call the procedure by name, drastically reducing network traffic and vastly improving execution performance since the code is pre-compiled."},hi:{q:"RDBMS में 'स्टोर्ड प्रोसीजर' (Stored Procedure) क्या है?",opts:["सॉफ़्टवेयर स्थापित करने का विवरण देने वाला एक मैनुअल","जटिल SQL स्टेटमेंट्स और तार्किक प्रोग्रामिंग कोड का एक पूर्व-संकलित संग्रह जो भौतिक रूप से संग्रहीत और सीधे डेटाबेस सर्वर इंजन के अंदर निष्पादित होता है","एक दिनचर्या जो कंप्यूटर को पुनरारंभ करती है","एक क्लाउड स्टोरेज प्रोटोकॉल"],ans:1,exp:"एक 'स्टोर्ड प्रोसीजर' अविश्वसनीय रूप से शक्तिशाली है। यह डेवलपर्स को IF/THEN स्टेटमेंट्स और लूप सहित SQL लॉजिक के व्यापक विखंडू लिखने और इसे सीधे डेटाबेस सर्वर पर सहेजने की अनुमति देता है। एप्लिकेशन बस प्रक्रिया को नाम से कॉल करते हैं, जिससे नेटवर्क ट्रैफ़िक काफी कम हो जाता है और निष्पादन प्रदर्शन में काफी सुधार होता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which database object is designed to execute completely automatically (fire) in direct response to a specific DML event (like INSERT, UPDATE, or DELETE) occurring on a table?",opts:["Index","Stored Procedure","Trigger","View"],ans:2,exp:"A 'Trigger' operates as an automated booby trap or safeguard attached to a table. The instant a user attempts a specific action (like UPDATING an employee's salary), the Trigger fires automatically. It can seamlessly run complex validation code, physically reject unauthorized changes, or stealthily write a timestamp to a security audit log."},hi:{q:"तालिका पर होने वाली किसी विशिष्ट DML घटना (जैसे INSERT, UPDATE, या DELETE) के सीधे जवाब में पूरी तरह से स्वचालित रूप से निष्पादित (fire) करने के लिए कौन सा डेटाबेस ऑब्जेक्ट डिज़ाइन किया गया है?",opts:["Index","Stored Procedure","Trigger","View"],ans:2,exp:"एक 'ट्रिगर' एक टेबल से जुड़े स्वचालित बूबी ट्रैप या सुरक्षागार्ड के रूप में कार्य करता है। जब कोई उपयोगकर्ता एक विशिष्ट कार्रवाई (जैसे कर्मचारी के वेतन को अद्यतन करना) का प्रयास करता है, तो ट्रिगर स्वचालित रूप से फायर हो जाता है। यह मूल रूप से जटिल सत्यापन कोड चला सकता है, अनधिकृत परिवर्तनों को अस्वीकार कर सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In SQL Transaction Control Language (TCL), what is the specific role of the 'COMMIT' command?",opts:["It cancels the current transaction","It permanently writes and locks all the temporary data modifications executed during the current transaction into the physical database disk","It creates a new table","It disconnects the user session"],ans:1,exp:"Databases utilize a safety buffer. When a user runs UPDATE or INSERT commands, the changes are stored in temporary transaction memory. The 'COMMIT' TCL command explicitly finalizes this process. It takes all pending changes from the current transaction block and permanently burns them into the physical hard drive structure, making them visible to all other users."},hi:{q:"SQL ट्रांजैक्शन कंट्रोल लैंग्वेज (TCL) में, 'COMMIT' कमांड की विशिष्ट भूमिका क्या है?",opts:["यह वर्तमान लेनदेन को रद्द कर देता है","यह भौतिक डेटाबेस डिस्क में वर्तमान लेनदेन के दौरान निष्पादित सभी अस्थायी डेटा संशोधनों को स्थायी रूप से लिखता और लॉक करता है","यह एक नई तालिका बनाता है","यह उपयोगकर्ता सत्र (user session) को डिस्कनेक्ट करता है"],ans:1,exp:"डेटाबेस एक सुरक्षा बफर का उपयोग करते हैं। जब कोई उपयोगकर्ता अद्यतन या सम्मिलित आदेश चलाता है, तो परिवर्तन अस्थायी लेनदेन मेमोरी में संग्रहीत किए जाते हैं। 'COMMIT' TCL कमांड स्पष्ट रूप से इस प्रक्रिया को अंतिम रूप देता है। यह वर्तमान लेनदेन ब्लॉक से सभी लंबित परिवर्तनों को लेता है और उन्हें स्थायी रूप से भौतिक हार्ड ड्राइव संरचना में जला देता है।"}},
{type:"mcq",diff:"hard",en:{q:"What happens if a database administrator executes the 'ROLLBACK' TCL command?",opts:["The database server restarts","It undoes absolutely all uncommitted data changes made in the current active transaction, forcibly returning the database to its precise state prior to the transaction starting","It reverses the last COMMIT command","It rolls the table layout upside down"],ans:1,exp:"The 'ROLLBACK' command acts as the ultimate abort switch for transactions. If a complex batch of SQL updates encounters a severe mathematical error halfway through, triggering a ROLLBACK immediately wipes the temporary memory. It physically reverses any partial data changes, ensuring the database remains completely pristine and mathematically consistent."},hi:{q:"यदि कोई डेटाबेस व्यवस्थापक 'ROLLBACK' TCL कमांड निष्पादित करता है तो क्या होता है?",opts:["डेटाबेस सर्वर पुनरारंभ होता है","यह वर्तमान सक्रिय लेन-देन में किए गए सभी अप्रतिबद्ध (uncommitted) डेटा परिवर्तनों को बिल्कुल पूर्ववत (undoes) कर देता है, बलपूर्वक डेटाबेस को लेन-देन शुरू होने से पहले उसकी सटीक स्थिति में लौटा देता है","यह अंतिम COMMIT कमांड को उलट देता है","यह टेबल लेआउट को उल्टा घुमाता है"],ans:1,exp:"'ROLLBACK' कमांड लेन-देन के लिए अंतिम निरस्त (abort) स्विच के रूप में कार्य करता है। यदि SQL अपडेट के एक जटिल बैच को बीच में एक गंभीर गणितीय त्रुटि का सामना करना पड़ता है, तो ROLLBACK ट्रिगर करने से तुरंत अस्थायी मेमोरी मिट जाती है। यह भौतिक रूप से किसी भी आंशिक डेटा परिवर्तन को उलट देता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the absolute maximum structural file size limit enforced by Microsoft for a single Access (.accdb) database file?",opts:["500 MB","2 Gigabytes (2 GB)","10 Gigabytes (10 GB)","Unlimited"],ans:1,exp:"Microsoft Access is engineered as a desktop, light-to-medium relational database. Its internal engine (ACE/Jet) enforces a strict, unbendable physical file size ceiling of precisely 2 Gigabytes (2 GB) per database file. Once this hard limit is reached, Access physically locks the database, strictly prohibiting any new data from being inserted until the file is compacted or upsized."},hi:{q:"Microsoft द्वारा एकल Access (.accdb) डेटाबेस फ़ाइल के लिए पूर्ण अधिकतम संरचनात्मक फ़ाइल आकार सीमा (file size limit) क्या लागू की गई है?",opts:["500 MB","2 गीगाबाइट (2 GB)","10 गीगाबाइट (10 GB)","असीमित (Unlimited)"],ans:1,exp:"Microsoft Access को डेस्कटॉप, हल्के से मध्यम रिलेशनल डेटाबेस के रूप में इंजीनियर किया गया है। इसका आंतरिक इंजन (ACE/Jet) प्रति डेटाबेस फ़ाइल 2 गीगाबाइट (2 GB) की सख्त, न झुकने वाली भौतिक फ़ाइल आकार की सीमा लागू करता है। एक बार यह सीमा पूरी हो जाने पर, एक्सेस भौतिक रूप से डेटाबेस को लॉक कर देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which built-in MS Access maintenance utility must be routinely run to reclaim hidden wasted space and drastically improve query execution speeds?",opts:["Disk Defragmenter","Compact and Repair Database","Query Optimizer","Macro Builder"],ans:1,exp:"When records are deleted in Access, the engine leaves the physical memory space totally blank and fragmented, bloating the file size wildly. The 'Compact and Repair' administrative tool actively rewrites the entire internal database structure, physically deleting the ghost spaces, shrinking the .accdb file size, repairing corrupt internal pointers, and optimizing index speeds."},hi:{q:"छिपे हुए व्यर्थ स्थान को पुनः प्राप्त करने और क्वेरी निष्पादन गति में भारी सुधार करने के लिए किस अंतर्निहित (built-in) MS Access रखरखाव उपयोगिता को नियमित रूप से चलाया जाना चाहिए?",opts:["डिस्क डीफ़्रेग्मेंटर","कॉम्पैक्ट और रिपेयर डेटाबेस (Compact and Repair Database)","क्वेरी ऑप्टिमाइज़र","मैक्रो बिल्डर"],ans:1,exp:"जब एक्सेस में रिकॉर्ड हटा दिए जाते हैं, तो इंजन भौतिक मेमोरी स्पेस को पूरी तरह से खाली और खंडित छोड़ देता है, जिससे फ़ाइल का आकार बेतहाशा बढ़ जाता है। 'कॉम्पैक्ट और रिपेयर' प्रशासनिक उपकरण सक्रिय रूप से संपूर्ण आंतरिक डेटाबेस संरचना को फिर से लिखता है, भूत स्थानों को भौतिक रूप से हटाता है, .accdb फ़ाइल का आकार कम करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In MS Access, what critical performance-enhancing limitation separates the 'Short Text' data type from the 'Long Text' (Memo) data type?",opts:["Long Text cannot hold numbers","Short Text fields can be effectively indexed for high-speed searching and sorting, whereas Long Text fields structurally cannot be indexed comprehensively","Short Text can hold images","There is no difference"],ans:1,exp:"Indexing is critical for speed. The Access engine can aggressively build high-speed, structural search indexes on 'Short Text' fields because their maximum length is predictably capped at 255 bytes. Conversely, 'Long Text' fields, capable of holding 65k characters, cannot be fully indexed in the same rapid manner, resulting in significantly slower searching algorithms."},hi:{q:"MS Access में, कौन सी महत्वपूर्ण प्रदर्शन-बढ़ाने वाली सीमा 'शॉर्ट टेक्स्ट' डेटा प्रकार को 'लॉन्ग टेक्स्ट' (मेमो) डेटा प्रकार से अलग करती है?",opts:["लॉन्ग टेक्स्ट संख्या नहीं रख सकता","शॉर्ट टेक्स्ट फ़ील्ड को हाई-स्पीड सर्चिंग और सॉर्टिंग के लिए प्रभावी ढंग से अनुक्रमित (indexed) किया जा सकता है, जबकि लॉन्ग टेक्स्ट फ़ील्ड को संरचनात्मक रूप से व्यापक रूप से अनुक्रमित नहीं किया जा सकता है","संक्षिप्त पाठ चित्र धारण कर सकता है","कोई अंतर नहीं है"],ans:1,exp:"गति के लिए अनुक्रमण (Indexing) महत्वपूर्ण है। एक्सेस इंजन आक्रामक रूप से 'शॉर्ट टेक्स्ट' फ़ील्ड पर हाई-स्पीड, स्ट्रक्चरल सर्च इंडेक्स बना सकता है क्योंकि उनकी अधिकतम लंबाई 255 बाइट्स पर अनुमानित है। इसके विपरीत, 'लॉन्ग टेक्स्ट' फ़ील्ड, जो 65k वर्ण रखने में सक्षम हैं, उसी तीव्र गति से पूरी तरह से अनुक्रमित नहीं किए जा सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which specialized system table in MS Access automatically tracks and stores the hidden metadata regarding every single table, query, form, and macro existing in the database?",opts:["MSysObjects","SystemTableData","MasterIndex","RootData"],ans:0,exp:"The 'MSysObjects' table is the secret neurological center of an Access database. It is a hidden, highly protected system table that actively maintains a constant directory of every object. It stores the exact object names, their creation timestamps, integer type codes (e.g., Type 1 for local tables), and structural pointers. Users should never manually alter it."},hi:{q:"MS Access में कौन सी विशेष प्रणाली तालिका स्वचालित रूप से डेटाबेस में मौजूद प्रत्येक तालिका, क्वेरी, फॉर्म और मैक्रो के संबंध में छिपे हुए मेटाडेटा को ट्रैक और संग्रहीत करती है?",opts:["MSysObjects","SystemTableData","MasterIndex","RootData"],ans:0,exp:"'MSysObjects' तालिका एक्सेस डेटाबेस का गुप्त तंत्रिका केंद्र है। यह एक छिपी हुई, अत्यधिक संरक्षित प्रणाली तालिका है जो सक्रिय रूप से प्रत्येक वस्तु की निरंतर निर्देशिका (directory) बनाए रखती है। यह सटीक वस्तु नाम, उनके निर्माण टाइमस्टैम्प, पूर्णांक प्रकार कोड (जैसे, स्थानीय तालिकाओं के लिए टाइप 1), और संरचनात्मक पॉइंटर्स संग्रहीत करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the MS Access Query Design grid, how does the engine mathematically interpret multiple criteria typed horizontally on the EXACT SAME 'Criteria' row?",opts:["It ignores them completely","It applies a logical OR condition","It tightly applies a strict logical AND condition, demanding both parameters be completely true simultaneously","It adds the values together"],ans:2,exp:"This is fundamental to Access Query By Example (QBE) logic. If a user types 'London' under the City column, and '>5000' horizontally under the Sales column on the exact same row, Access enforces a strict 'AND' gate. The query will only extract a record if the customer lives in London AND mathematically has over 5000 in sales simultaneously."},hi:{q:"MS Access Query Design ग्रिड में, इंजन गणितीय रूप से बिल्कुल एक ही 'Criteria' (मानदंड) पंक्ति पर क्षैतिज रूप से (horizontally) टाइप किए गए कई मानदंडों की व्याख्या कैसे करता है?",opts:["यह उन्हें पूरी तरह नज़रअंदाज़ कर देता है","यह एक तार्किक OR शर्त लागू करता है","यह एक सख्त तार्किक AND शर्त को मजबूती से लागू करता है, मांग करता है कि दोनों पैरामीटर एक साथ पूरी तरह से सत्य हों","यह मानों को एक साथ जोड़ता है"],ans:2,exp:"यह Access Query By Example (QBE) तर्क के लिए मौलिक है। यदि कोई उपयोगकर्ता शहर कॉलम के नीचे 'लंदन' टाइप करता है, और उसी पंक्ति में बिक्री कॉलम के नीचे क्षैतिज रूप से '>5000' टाइप करता है, तो एक्सेस एक सख्त 'AND' गेट लागू करता है। क्वेरी केवल एक रिकॉर्ड निकालेगी यदि ग्राहक लंदन में रहता है और साथ ही उसकी बिक्री 5000 से अधिक है।"}},
{type:"mcq",diff:"hard",en:{q:"Conversely, if criteria are typed vertically on completely DIFFERENT staggered rows (the 'Or' rows) in the Access Query grid, how is the logic interpreted?",opts:["It applies a logical OR condition, meaning a record is pulled if it satisfies either the first row's condition OR the second row's condition independently","It applies an AND condition","It creates a Join","It deletes the records"],ans:0,exp:"When building queries visually, utilizing multiple staggered 'Or' rows changes the logical gate entirely. If 'London' is typed on row 1, and 'Paris' is typed below it on row 2, Access constructs an 'OR' logic gate. It independently scans the table and grabs any record matching London, OR any record matching Paris, drastically widening the result set."},hi:{q:"इसके विपरीत, यदि एक्सेस क्वेरी ग्रिड में पूरी तरह से अलग कंपित पंक्तियों (staggered rows) ('Or' पंक्तियों) पर लंबवत (vertically) रूप से मानदंड टाइप किए जाते हैं, तो तर्क की व्याख्या कैसे की जाती है?",opts:["यह एक तार्किक 'OR' शर्त लागू करता है, जिसका अर्थ है कि एक रिकॉर्ड खींचा जाता है यदि वह या तो पहली पंक्ति की शर्त या दूसरी पंक्ति की शर्त को स्वतंत्र रूप से संतुष्ट करता है","यह 'AND' स्थिति लागू करता है","यह एक जॉइन (Join) बनाता है","यह रिकॉर्ड को हटा देता है"],ans:0,exp:"क्वेरीज़ को दृष्टिगत रूप से बनाते समय, कई कंपित 'Or' पंक्तियों का उपयोग तार्किक गेट को पूरी तरह से बदल देता है। यदि पंक्ति 1 पर 'लंदन' टाइप किया गया है, और पंक्ति 2 पर 'पेरिस' टाइप किया गया है, तो एक्सेस एक 'OR' लॉजिक गेट बनाता है। यह स्वतंत्र रूप से टेबल को स्कैन करता है और लंदन से मेल खाने वाले किसी भी रिकॉर्ड, या पेरिस से मेल खाने वाले किसी भी रिकॉर्ड को पकड़ लेता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly specialized MS Access Domain Aggregate function is used in forms or VBA to fetch a single, specific value from an external table without needing a full joined query?",opts:["DSum()","DLookUp()","DCount()","DGet()"],ans:1,exp:"The 'DLookUp()' function operates essentially like an incredibly precise VLOOKUP from Excel, but engineered for relational tables. The syntax is DLookUp(\"Return_Field\", \"Table_Name\", \"Criteria\"). It launches a surgical strike into a separate, unlinked table, hunts down the exact record matching the criteria, and retrieves that single solitary piece of data back to the active form."},hi:{q:"संपूर्ण सम्मिलित (joined) क्वेरी की आवश्यकता के बिना बाहरी तालिका से एकल, विशिष्ट मान प्राप्त करने के लिए फ़ॉर्म या VBA में किस अत्यधिक विशिष्ट MS Access डोमेन एग्रीगेट फ़ंक्शन का उपयोग किया जाता है?",opts:["DSum()","DLookUp()","DCount()","DGet()"],ans:1,exp:"'DLookUp()' फ़ंक्शन अनिवार्य रूप से एक्सेल से अविश्वसनीय रूप से सटीक VLOOKUP की तरह काम करता है, लेकिन रिलेशनल टेबल के लिए इंजीनियर है। सिंटैक्स DLookUp(\"Return_Field\", \"Table_Name\", \"Criteria\") है। यह एक अलग, बिना लिंक की गई तालिका में एक सर्जिकल स्ट्राइक शुरू करता है, मानदंड से मेल खाने वाले सटीक रिकॉर्ड का शिकार करता है, और डेटा के उस एकल टुकड़े को पुनः प्राप्त करता है।"}},
{type:"mcq",diff:"hard",en:{q:"How does the 'IIf()' (Immediate If) functional syntax operate in an Access Query calculated field?",opts:["It strictly adds two numbers","It constructs a loop","It takes exactly three arguments: a logical condition, the output if the mathematical condition evaluates to TRUE, and the output if it evaluates to FALSE","It deletes null rows"],ans:2,exp:"The 'IIf()' function introduces dynamic, row-by-row programmatic logic directly into standard queries. Formatted as `IIf(Condition, TruePart, FalsePart)`, the engine assesses the condition per row. Example: `IIf([Score]>50, \"Pass\", \"Fail\")`. It instantly populates the calculated field with \"Pass\" if the score is mathematically greater than 50, otherwise outputting \"Fail\"."},hi:{q:"एक्सेस क्वेरी परिकलित क्षेत्र (calculated field) में 'IIf()' (Immediate If) कार्यात्मक सिंटैक्स कैसे काम करता है?",opts:["यह सख्ती से दो संख्याएँ जोड़ता है","यह एक लूप बनाता है","यह ठीक तीन तर्क (arguments) लेता है: एक तार्किक स्थिति, आउटपुट यदि गणितीय स्थिति TRUE का मूल्यांकन करती है, और आउटपुट यदि यह FALSE का मूल्यांकन करती है","यह शून्य (null) पंक्तियों को हटा देता है"],ans:2,exp:"'IIf()' फ़ंक्शन सीधे मानक प्रश्नों में गतिशील, पंक्ति-दर-पंक्ति प्रोग्रामेटिक तर्क (programmatic logic) पेश करता है। `IIf(Condition, TruePart, FalsePart)` के रूप में स्वरूपित, इंजन प्रति पंक्ति स्थिति का आकलन करता है। उदाहरण: `IIf([Score]>50, \"Pass\", \"Fail\")`। यदि स्कोर 50 से अधिक है, तो यह तुरंत परिकलित फ़ील्ड को \"Pass\" से भर देता है, अन्यथा \"Fail\" आउटपुट करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In creating robust databases, creating 'Indexes' massively accelerates data retrieval (SELECT queries). What is the major functional drawback of creating too many indexes?",opts:["It turns the database offline","It drastically slows down data modification operations (INSERT, UPDATE, DELETE) because the engine must physically rewrite the heavy index tree structure on every single change","It changes text to lowercase","It corrupts the network"],ans:1,exp:"Indexes are a strict double-edged sword in database architecture. While an index structure (like a B-Tree) massively turbocharges READ operations (SELECT) by providing quick pointers, it actively penalizes WRITE operations. Every time a new row is INSERTED or UPDATED, the SQL engine is forced to waste processing cycles physically re-sorting and rebuilding the heavy index tables."},hi:{q:"मजबूत डेटाबेस बनाने में, 'इंडेक्स' बनाने से डेटा पुनर्प्राप्ति (SELECT queries) में भारी तेजी आती है। बहुत अधिक इंडेक्स बनाने का प्रमुख कार्यात्मक दोष (drawback) क्या है?",opts:["यह डेटाबेस को ऑफ़लाइन कर देता है","यह डेटा संशोधन संचालन (INSERT, UPDATE, DELETE) को काफी धीमा कर देता है क्योंकि इंजन को हर एक बदलाव पर भारी इंडेक्स ट्री संरचना को भौतिक रूप से फिर से लिखना पड़ता है","यह टेक्स्ट को लोअरकेस में बदल देता है","यह नेटवर्क को भ्रष्ट कर देता है"],ans:1,exp:"इंडेक्स डेटाबेस आर्किटेक्चर में एक सख्त दोधारी तलवार है। जबकि एक इंडेक्स संरचना बड़े पैमाने पर READ संचालन (SELECT) को टर्बोचार्ज करती है, यह सक्रिय रूप से WRITE संचालन को दंडित करती है। हर बार जब कोई नई पंक्ति डाली या अपडेट की जाती है, तो SQL इंजन को भारी इंडेक्स तालिकाओं को भौतिक रूप से फिर से सॉर्ट करने और फिर से बनाने में प्रोसेसिंग चक्र बर्बाद करने के लिए मजबूर किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"If Table A and Table B share a One-to-One (1:1) relationship, how are the primary and foreign keys architecturally structured?",opts:["Table A has no keys","Table B uses a multi-valued field","The Primary Key of Table A identically serves as both the Primary Key AND the Foreign Key in Table B, firmly locking them together","They use a Junction Table"],ans:2,exp:"A One-to-One (1:1) relational architecture is exceptionally rigid. It is used to logically split a massive table into two for security or performance. To physically enforce this 1:1 bond, the database engineer takes the Primary Key from the master table and designates it as both the Primary Key AND the Foreign Key in the secondary table, ensuring absolute synchronization."},hi:{q:"यदि तालिका A और तालिका B वन-टू-वन (1:1) संबंध साझा करते हैं, तो प्राथमिक और विदेशी कुंजियाँ (keys) वास्तुशिल्प रूप से कैसे संरचित होती हैं?",opts:["टेबल A में कोई कुंजी नहीं है","तालिका B बहु-मूल्यवान क्षेत्र का उपयोग करती है","तालिका A की प्राथमिक कुंजी (Primary Key) तालिका B में प्राथमिक कुंजी और विदेशी कुंजी (Foreign Key) दोनों के रूप में समान रूप से कार्य करती है, उन्हें मजबूती से एक साथ बंद कर देती है","वे एक जंक्शन टेबल का उपयोग करते हैं"],ans:2,exp:"एक वन-टू-वन (1:1) संबंधपरक वास्तुकला असाधारण रूप से कठोर है। इसका उपयोग सुरक्षा या प्रदर्शन के लिए एक विशाल तालिका को दो में तार्किक रूप से विभाजित करने के लिए किया जाता है। इस 1:1 बांड को भौतिक रूप से लागू करने के लिए, डेटाबेस इंजीनियर मास्टर टेबल से प्राइमरी की लेता है और इसे सेकेंडरी टेबल में प्राइमरी की और फॉरेन की दोनों के रूप में नामित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following defines a 'Candidate Key' in relational database theory?",opts:["A key that is used only for sorting","Any column or minimal combination of columns that contains enough unique entropy to distinctly identify a row, thereby qualifying as a 'candidate' to be chosen as the Primary Key","A key from an external database","A foreign key in a view"],ans:1,exp:"In relational theory, a table might possess multiple fields capable of uniqueness (e.g., an Employee ID, a Social Security Number, and an Email Address). Each of these uniquely identifying columns is formally termed a 'Candidate Key'. The database architect analyzes these candidates and ultimately selects the most efficient, non-changing one to be the actual Primary Key."},hi:{q:"रिलेशनल डेटाबेस थ्योरी में 'कैंडिडेट की' (Candidate Key) को निम्नलिखित में से कौन परिभाषित करता है?",opts:["एक कुंजी जिसका उपयोग केवल छँटाई के लिए किया जाता है","कोई भी कॉलम या कॉलम का न्यूनतम संयोजन जिसमें एक पंक्ति को स्पष्ट रूप से पहचानने के लिए पर्याप्त अनूठी एन्ट्रापी होती है, जिससे प्राइमरी की के रूप में चुने जाने वाले 'उम्मीदवार' के रूप में योग्यता प्राप्त होती है","बाहरी डेटाबेस से एक कुंजी","एक दृश्य (view) में एक विदेशी कुंजी"],ans:1,exp:"रिलेशनल थ्योरी में, एक तालिका में विशिष्टता में सक्षम कई क्षेत्र हो सकते हैं (जैसे, कर्मचारी आईडी, सामाजिक सुरक्षा संख्या और ईमेल पता)। इनमें से प्रत्येक विशिष्ट रूप से पहचानने वाले कॉलम को औपचारिक रूप से 'उम्मीदवार कुंजी' (Candidate Key) कहा जाता है। डेटाबेस आर्किटेक्ट इन उम्मीदवारों का विश्लेषण करता है और अंततः वास्तविक प्राइमरी की के रूप में सबसे कुशल, गैर-बदलने वाले को चुनता है।"}},
// HARD - TRUE/FALSE (2 Questions)
{type:"tf",diff:"hard",en:{q:"A single database table can simultaneously possess three separate Primary Keys actively enforcing logic on different columns.",opts:["True","False"],ans:1,exp:"False. By strict mathematical relational database laws, a single table can possess absolutely only ONE defined Primary Key object. While that single Primary Key can be structurally composed of multiple combined columns (creating a 'Composite Key'), it is still treated by the SQL engine as one singular, unified Primary Key object per table."},hi:{q:"एक एकल डेटाबेस तालिका एक साथ तीन अलग-अलग प्राइमरी कीज़ (Primary Keys) रख सकती है जो सक्रिय रूप से विभिन्न कॉलम पर तर्क लागू कर सकती हैं।",opts:["सही","गलत"],ans:1,exp:"गलत। सख्त गणितीय रिलेशनल डेटाबेस कानूनों द्वारा, एक एकल तालिका में बिल्कुल केवल एक परिभाषित प्राइमरी की (Primary Key) ऑब्जेक्ट हो सकता है। जबकि वह एकल प्राइमरी की संरचनात्मक रूप से कई संयुक्त स्तंभों (एक 'कम्पोजिट की' बनाना) से बना हो सकता है, फिर भी इसे SQL इंजन द्वारा प्रति तालिका एक एकल, एकीकृत प्राइमरी की ऑब्जेक्ट के रूप में माना जाता है।"}},
{type:"tf",diff:"hard",en:{q:"In most robust SQL RDBMS engines (like MySQL or Oracle), major DDL commands like DROP TABLE or CREATE TABLE are auto-committed and strictly cannot be reversed using the ROLLBACK command.",opts:["True","False"],ans:0,exp:"True. In almost all standard relational database systems, Data Definition Language (DDL) statements (CREATE, ALTER, DROP, TRUNCATE) force an immediate, implicit COMMIT operation. This permanently alters the physical system dictionary architecture, meaning if you execute a DROP TABLE, you cannot salvage the structure by issuing a ROLLBACK command."},hi:{q:"अधिकांश मजबूत SQL RDBMS इंजन (जैसे MySQL या Oracle) में, DROP TABLE या CREATE TABLE जैसे प्रमुख DDL कमांड ऑटो-कमिटेड होते हैं और ROLLBACK कमांड का उपयोग करके सख्ती से उलटा नहीं किया जा सकता है।",opts:["सही","गलत"],ans:0,exp:"सही। लगभग सभी मानक रिलेशनल डेटाबेस सिस्टम में, डेटा डेफिनिशन लैंग्वेज (DDL) स्टेटमेंट्स (CREATE, ALTER, DROP, TRUNCATE) एक तत्काल, अंतर्निहित COMMIT ऑपरेशन को मजबूर करते हैं। यह स्थायी रूप से भौतिक प्रणाली वास्तुकला को बदल देता है, जिसका अर्थ है कि यदि आप DROP TABLE निष्पादित करते हैं, तो आप ROLLBACK कमांड जारी करके संरचना को नहीं बचा सकते हैं।"}}
];
